# --------------------------------------------------------------------------- #
# Server-side session. Guarded by a lock: the compute thread reads it while the
# UI may reload it via upload.
#   sides: name -> {arr, spacing, offset_xyz, side}  (volume side)
#              or  {mesh, side, offset_xyz}           (bare-mesh side)
#   is_mesh: True when the session holds only a surface (no volume to measure)
# --------------------------------------------------------------------------- #
SESSION: dict = {"arr": None, "spacing": None, "meta": None, "sides": {},
                 "is_mesh": False}
_LOCK = threading.Lock()
_LAST_MESH = {"thickness": None, "deviation": None, "thickness_second": None}
# Region list from the last Mode-A thickness compute ([{label, volume_cm3,
# boneness}], see core.pipeline.analyze_thickness) — feeds the per-region
# statistics figure. Mode B has no per-region breakdown (single registered
# surface), so this is left as-is (stale/previous Mode A regions) when in
# Mode B; the figures panel only reads it in the Mode A branch below.
_LAST_REGIONS: list[dict] | None = None

# Monotonic session generation: bumped whenever a new scan/mesh is adopted, so a
# thumbnail cache keyed by (generation, side) is invalidated automatically.
_SESSION_GEN = 0
# (generation, side) -> [{label, volume_cm3, boneness, thumb}] region previews.
_THUMB_CACHE: dict[tuple[int, str], list[dict]] = {}
_THUMB_LOCK = threading.Lock()


# --------------------------------------------------------------------------- #
# Runtime config (Share panel + UI switcher). Read the same file the API uses.
# --------------------------------------------------------------------------- #
def read_public_config() -> dict:
    """Mirror of ``/api/config``: public share URLs from public_urls.json."""
    pub: dict = {}
    if PUBLIC_URLS.exists():
        try:
            pub = json.loads(PUBLIC_URLS.read_text())
        except Exception:  # noqa: BLE001
            pub = {}
    return {
        "app": "3Dorth",
        "react_url": pub.get("react_url"),
        "trame_url": pub.get("trame_url"),
        "public": bool(pub.get("react_url") or pub.get("trame_url")),
    }


def _bump_session_gen() -> int:
    """Advance the session generation (invalidates the thumbnail cache)."""
    global _SESSION_GEN
    _SESSION_GEN += 1
    return _SESSION_GEN


def _adopt_volume_session(arr, spacing, meta, layout="auto") -> None:
    sides = pipeline.split_sides(arr, spacing, layout=layout)
    with _LOCK:
        SESSION.update(arr=arr, spacing=spacing, meta=meta, sides=sides,
                       is_mesh=False)
    _bump_session_gen()


def _adopt_mesh_session(mesh, meta) -> None:
    sides = {"mesh": {"mesh": mesh, "side": "mesh", "offset_xyz": (0.0, 0.0, 0.0)}}
    with _LOCK:
        SESSION.update(arr=None, spacing=None, meta=meta, sides=sides,
                       is_mesh=True)
    _bump_session_gen()


def _load_source(path: Path, layout: str = "auto") -> None:
    """Ingest an uploaded/demo path; branch mesh vs volume like /api/upload."""
    if is_mesh(path):
        mesh = pipeline.load_mesh_source(path)
        meta = {"format": path.suffix.lstrip("."), "kind": "mesh",
                "n_points": int(mesh.n_points)}
        _adopt_mesh_session(mesh, meta)
    else:
        arr, spacing, meta = pipeline.load_volume_from_source(path, WORKDIR)
        _adopt_volume_session(arr, spacing, meta, layout=layout)


def _side_names() -> list[str]:
    with _LOCK:
        return list(SESSION["sides"].keys())


def _refresh_session_ui() -> None:
    """Push session-derived UI state (side options, mesh flag, sensible defaults)."""
    names = _side_names()
    is_mesh_sess = bool(SESSION.get("is_mesh"))
    labels = {"left": "Left", "right": "Right", "full": "Full", "mesh": "Mesh"}
    opts = [{"title": labels.get(n, n.capitalize()), "value": n} for n in names]
    bilateral = set(names) == {"left", "right"}
    # Bilateral scans get a "Both" thickness option that renders left + right
    # together (each coloured by its own cortical thickness). UI-only side value.
    # It is offered ONLY on the thickness-side selector (side_thickness_options),
    # never on the reference/target selectors (which need a single side each).
    both_allowed = bilateral and not is_mesh_sess
    thickness_opts = opts + (
        [{"title": "Both (left + right)", "value": "both"}] if both_allowed else []
    )

    state.side_options = opts
    state.side_thickness_options = thickness_opts
    state.session_sides = names
    state.is_mesh_session = is_mesh_sess
    state.is_bilateral = bilateral
    # Keep the active selectors valid for the current session. 'both' is a valid
    # thickness selection on a bilateral volume session.
    valid_sides = names + (["both"] if both_allowed else [])
    if state.side not in valid_sides:
        state.side = names[0] if names else "full"
    if bilateral:
        state.ref_side, state.tgt_side = "left", "right"
    elif names:
        # Non-bilateral: reference/target both fall back to the only side.
        state.ref_side = state.tgt_side = names[0]
    # A bare-mesh session cannot do Mode-A thickness (needs a volume wall).
    if is_mesh_sess and state.mode == "A":
        state.mode = "B"
    state.meta_html = _meta_html()
    # A fresh scan invalidates any previously shown region previews.
    state.region_thumbs = []
    state.region_thumbs_side = ""
    state.region_thumbs_loading = False
    state.region_thumbs_msg = ""
    state.region_label = None
    # Re-point the MPR viewer at the new session's active volume (or hide it for a
    # bare-mesh session). Safe to call inside a `with state` block.
    _mpr_reset_for_side()
    # Re-seed the oblique plane widget at the new session's active volume side.
    _oblique_reset_for_side()
    # A fresh scan invalidates any cached compare-mode registration.
    with _COMPARE_REG_LOCK:
        _COMPARE_REG_CACHE.clear()
    state.compare_available = (not is_mesh_sess) and bilateral
    if state.compare_active:
        _compare_reset()


def _downloads_url(thumb: str | None) -> str | None:
    """Rewrite a pipeline ``/api/exports/<file>`` URL onto the trame server's
    ``/downloads`` mount (the exports dir is served there). ``None`` stays None."""
    if not thumb:
        return None
    return f"/downloads/{Path(thumb).name}"


def load_region_thumbnails(*_a, **_k) -> None:
    """Compute (or serve from cache) small per-region previews for the active
    thickness side, on a background thread, and push them to the UI.

    Calls ``core.pipeline.region_thumbnails`` DIRECTLY (trame is server-side).
    Files land under ``outputs/exports`` (served at ``/downloads``). Cached per
    (session generation, side). Skipped for a bare-mesh session (no volume
    regions) and for the deviation view. Render takes ~5-10 s; the UI shows a
    spinner meanwhile.
    """
    if bool(SESSION.get("is_mesh")):
        return
    if state.mode == "B" and state.b_view == "deviation":
        return
    side_key = state.side
    with _LOCK:
        gen = _SESSION_GEN
        side = SESSION["sides"].get(side_key)
    if side is None or side.get("arr") is None:
        return

    cache_key = (gen, side_key)
    with _THUMB_LOCK:
        cached = _THUMB_CACHE.get(cache_key)
    if cached is not None:
        with state:
            state.region_thumbs = cached
            state.region_thumbs_side = side_key
            state.region_thumbs_loading = False
            state.region_thumbs_msg = (
                f"{len(cached)} region(s)." if cached else "No bone regions found."
            )
        state.flush()
        return

    with state:
        state.region_thumbs_loading = True
        state.region_thumbs = []
        state.region_thumbs_side = side_key
        state.region_thumbs_msg = "Rendering region previews… (~5–10 s)"
    state.flush()

    def _job():
        try:
            thumbs = pipeline.region_thumbnails(
                side["arr"], side["spacing"], P.default_parameters(),
                EXPORTS_DIR, f"{gen}_{side_key}",
            )
            for t in thumbs:
                t["thumb"] = _downloads_url(t.get("thumb"))
            with _THUMB_LOCK:
                _THUMB_CACHE[cache_key] = thumbs
            # Only apply if the session/side is still what we computed for.
            with _LOCK:
                still_current = (_SESSION_GEN == gen and state.side == side_key)
            with state:
                if still_current:
                    state.region_thumbs = thumbs
                    state.region_thumbs_side = side_key
                state.region_thumbs_loading = False
                state.region_thumbs_msg = (
                    f"{len(thumbs)} region(s)." if thumbs
                    else "No bone regions found.")
            state.flush()
        except Exception as e:  # noqa: BLE001
            traceback.print_exc()
            with state:
                state.region_thumbs_loading = False
                state.region_thumbs_msg = f"Preview render failed: {e}"
            state.flush()

    threading.Thread(target=_job, daemon=True).start()


ctrl.load_region_thumbnails = load_region_thumbnails


