state.cmp_tgt_img_sagittal = ""
state.cmp_tgt_ix = 0                  # matched target voxel (display only)
state.cmp_tgt_iy = 0
state.cmp_tgt_iz = 0
state.cmp_tgt_in_bounds = True
state.cmp_reliable = True             # inlier_fraction >= 0.30 (same gate as the API)
state.cmp_rms = 0.0
state.cmp_inlier_fraction = 0.0
state.cmp_reg_note = ""
state.cmp_msg = ""                    # status / error line for the compare panel
state.cmp_busy = False
state.cmp_note = ("Research / de-identified — not for diagnostic use. Planes are "
                  "array-oriented (no radiological A/P/S/I laterality). The matched "
                  "TARGET slice is a REGISTRATION ESTIMATE, not a direct measurement.")

# plane -> (crosshair-index state key, per-plane index state key, n-slices key)
_MPR_PLANE_STATE = {
    "axial": ("mpr_iz", "mpr_idx_axial", "mpr_n_axial"),
    "coronal": ("mpr_iy", "mpr_idx_coronal", "mpr_n_coronal"),
    "sagittal": ("mpr_ix", "mpr_idx_sagittal", "mpr_n_sagittal"),
}


def _mpr_active_side() -> dict | None:
    """Return the volume-side dict feeding the MPR viewer (None for mesh/empty).

    Uses the thickness side selector; falls back to the reference side (Mode B) or
    the first volume side so the panels always show something for a volume scan.
    """
    if bool(SESSION.get("is_mesh")):
        return None
    with _LOCK:
        sides = dict(SESSION["sides"])
    for key in (state.side, state.ref_side, *sides.keys()):
        sd = sides.get(key)
        if sd is not None and sd.get("arr") is not None:
            state.mpr_side = key
            return sd
    return None


def _mpr_render_plane(side: dict, plane: str) -> str:
    """Render one plane to a base64 data URI via the shared slice pipeline."""
    import base64
    idx_key = _MPR_PLANE_STATE[plane][1]
    index = int(state[idx_key])
    png = mpr.render_slice_png(
        side["arr"], side["spacing"], plane, index,
        window=float(state.mpr_window), level=float(state.mpr_level), max_dim=384,
    )
    return "data:image/png;base64," + base64.b64encode(png).decode("ascii")


def _mpr_refresh_images(*_a, **_k) -> None:
    """Re-render all three slice PNGs from the current crosshair/window/level."""
    side = _mpr_active_side()
    if side is None:
        with state:
            state.mpr_available = False
        state.flush()
        return
    with state:
        state.mpr_available = True
        state.mpr_img_axial = _mpr_render_plane(side, "axial")
        state.mpr_img_coronal = _mpr_render_plane(side, "coronal")
        state.mpr_img_sagittal = _mpr_render_plane(side, "sagittal")
    state.flush()


def _mpr_sync_from_voxel(ijk) -> None:
    """Adopt a voxel (ix,iy,iz): set crosshair + per-plane slice indices (clamped),
    exactly like the API's slices_from_voxel, then re-render the three panels."""
    side = _mpr_active_side()
    if side is None:
        return
    shape = side["arr"].shape  # (nz, ny, nx)
    ix, iy, iz = (int(v) for v in ijk)
    sl = mpr.slices_from_voxel((ix, iy, iz), shape)
    with state:
        state.mpr_ix = mpr.clamp_index(shape, "sagittal", ix)
        state.mpr_iy = mpr.clamp_index(shape, "coronal", iy)
        state.mpr_iz = mpr.clamp_index(shape, "axial", iz)
        state.mpr_idx_axial = sl["axial"]
        state.mpr_idx_coronal = sl["coronal"]
        state.mpr_idx_sagittal = sl["sagittal"]
    _mpr_refresh_images()


def _mpr_reset_for_side(*_a, **_k) -> None:
    """Reset MPR extents + crosshair to the center of the active volume side."""
    side = _mpr_active_side()
    if side is None:
        with state:
            state.mpr_available = False
        state.flush()
        return
    info = mpr.volume_info(side["arr"], side["spacing"], side["offset_xyz"],
                           side.get("side", state.mpr_side))
    nz, ny, nx = info["shape_zyx"]
    with state:
        state.mpr_available = True
        state.mpr_window = info["default_window"]
        state.mpr_level = info["default_level"]
        state.mpr_n_axial = info["n_slices"]["axial"]
        state.mpr_n_coronal = info["n_slices"]["coronal"]
        state.mpr_n_sagittal = info["n_slices"]["sagittal"]
    _mpr_sync_from_voxel((nx // 2, ny // 2, nz // 2))


def _mpr_on_plane_index_change(*_a, **_k) -> None:
    """A plane slider moved: mirror it into the crosshair voxel and re-render.

    axial idx -> iz, coronal idx -> iy, sagittal idx -> ix (per the fixed plane↔axis
    map). Keeps the crosshair and the three panels in sync from either direction.
    """
    with state:
        state.mpr_iz = int(state.mpr_idx_axial)
        state.mpr_iy = int(state.mpr_idx_coronal)
        state.mpr_ix = int(state.mpr_idx_sagittal)
    _mpr_refresh_images()


ctrl.mpr_refresh = _mpr_refresh_images
ctrl.mpr_reset = _mpr_reset_for_side


# --------------------------------------------------------------------------- #
# Oblique (arbitrary-tilt) cross-section.
#
# A pyvista interactive plane widget on the 3D view gives an ARBITRARY
# (origin, normal) on every drag — not restricted to the three orthogonal
# planes. The widget callback renders the matching 2D reformat directly via
# core.viz.slice.render_oblique_png (the SAME function the locked
# /oblique-slice API endpoint calls), so the 3D cut and the 2D image are
# matched at every point by construction: the returned meta's basis (u, v)
# fully defines pixel<->world for that exact plane.
#
# BILATERAL: when the session has two distinct volume sides, the widget lives
# on the REFERENCE side and the SAME physical cut is mapped through the cached
# compare_registration 4x4 (core.pipeline.map_plane) onto the TARGET side —
# so BOTH bones' 2D reformats render as two boxes ("Reference bone" /
# "Target bone") above the plane controls, matching the API's
# /oblique-compare contract exactly (registers once, reused while the plane
# moves). Single-sided/mesh sessions fall back to the single-panel oblique.
#
# Display-only: this NEVER calls core.pipeline's thickness/deviation compute.
# The one-time registration (compare_registration) is cached, same as Compare
# mode; only the (fast) re-sample runs on every plane move. The widget
# survives plotter.clear()/clear_actors() (pyvista keeps widgets across scene
# rebuilds), so it stays put across Apply/Recompute and display-only recolors;
# only a side switch or a fresh session re-seeds it.
# --------------------------------------------------------------------------- #
OBLIQUE_WIDGET: dict = {"widget": None}
_OBLIQUE_MIN_RELIABLE_INLIER = 0.30


def _oblique_bilateral_sides() -> tuple[str, str] | None:
    """Pick the (reference, target) volume-side pair for the oblique-compare
    view, or None when the session isn't bilateral (mirrors
    ``_compare_sides_available``, kept independent so the oblique widget can
    stay on Mode A's reference/target choice regardless of Mode B state)."""
    with _LOCK:
        if SESSION.get("is_mesh"):
            return None
        sides = {k: v for k, v in SESSION["sides"].items() if v.get("arr") is not None}
    names = list(sides.keys())
    if len(names) < 2:
        return None
    ref = state.ref_side if state.ref_side in sides else names[0]
    tgt = state.tgt_side if (state.tgt_side in sides and state.tgt_side != ref) else (
        next((n for n in names if n != ref), names[0]))
    return ref, tgt


def _oblique_render(side: dict, origin, normal) -> None:
    """Render the SINGLE-panel oblique reformat for (origin, normal) and push
    it to state. Used for non-bilateral (single-sided / mesh) sessions."""
    png, meta = mpr.render_oblique_png(
        side["arr"], side["spacing"], side["offset_xyz"], origin, normal,
        size_mm=float(state.oblique_size_mm), px_mm=1.0, max_dim=384,
        window=float(state.oblique_window), level=float(state.oblique_level),
    )
    import base64
    with state:
        state.oblique_available = True
        state.oblique_origin = [float(x) for x in meta["origin_xyz_mm"]]
        state.oblique_normal = [float(x) for x in meta["normal"]]
        state.oblique_img = "data:image/png;base64," + base64.b64encode(png).decode("ascii")
    state.flush()


def _oblique_render_compare(ref_side: str, tgt_side: str, origin, normal) -> None:
    """Render BOTH bones' 2D reformats for the bilateral oblique-compare view.

    Registers reference<->target ONCE (cached via ``_get_compare_registration``
    — the SAME cache Compare mode uses, keyed on (ref,tgt,params,manual)), then
    maps the reference (origin, normal) onto the target via
    ``core.pipeline.map_plane`` and renders both reformats with
    ``core.viz.slice.render_oblique_png``. Surfaces the reliable/amber gate
    (inlier_fraction >= 0.30) — the target box is rendered regardless, never
    hidden, only flagged.
    """
    with _LOCK:
        ref = SESSION["sides"][ref_side]
        tgt = SESSION["sides"][tgt_side]
    reg = _get_compare_registration(ref_side, tgt_side)
    tgt_origin, tgt_normal = pipeline.map_plane(
        reg["ref_world_to_tgt_world"], origin, normal)

    size_mm, px_mm = float(state.oblique_size_mm), 1.0
    window, level = float(state.oblique_window), float(state.oblique_level)
    ref_png, ref_meta = mpr.render_oblique_png(
        ref["arr"], ref["spacing"], ref["offset_xyz"], origin, normal,
        size_mm=size_mm, px_mm=px_mm, max_dim=384, window=window, level=level)
    tgt_png, tgt_meta = mpr.render_oblique_png(
        tgt["arr"], tgt["spacing"], tgt["offset_xyz"], tgt_origin, tgt_normal,
        size_mm=size_mm, px_mm=px_mm, max_dim=384, window=window, level=level)

    reliable = reg["inlier_fraction"] >= _OBLIQUE_MIN_RELIABLE_INLIER
    note = ("registration is well-constrained" if reliable else
            "low overlap — the matched target reformat is unreliable "
            "(isolate the bone / adjust registration first)")

    import base64
    with state:
        state.oblique_available = True
        state.oblique_bilateral = True
        state.oblique_ref_side = ref_side
        state.oblique_tgt_side = tgt_side
        state.oblique_origin = [float(x) for x in ref_meta["origin_xyz_mm"]]
        state.oblique_normal = [float(x) for x in ref_meta["normal"]]
        state.oblique_tgt_origin = [float(x) for x in tgt_meta["origin_xyz_mm"]]
        state.oblique_tgt_normal = [float(x) for x in tgt_meta["normal"]]
        state.oblique_ref_img = "data:image/png;base64," + base64.b64encode(ref_png).decode("ascii")
        state.oblique_tgt_img = "data:image/png;base64," + base64.b64encode(tgt_png).decode("ascii")
        state.oblique_cmp_rms = round(float(reg["rms"]), 3)
        state.oblique_cmp_inlier_fraction = round(float(reg["inlier_fraction"]), 3)
        state.oblique_cmp_reliable = bool(reliable)
        state.oblique_cmp_reg_note = note
    state.flush()


def _on_oblique_widget(normal, origin) -> None:
    """pyvista plane-widget callback: (normal, origin) on every drag/create.

    Display-only — re-renders the 2D reformat(s) ONLY; never touches
    core.pipeline's thickness/deviation recompute. Bilateral sessions render
    BOTH boxes (registering once, then re-sampling on every move); otherwise
    falls back to the single-panel oblique.
    """
    origin = tuple(float(x) for x in origin)
    normal = tuple(float(x) for x in normal)
    picked = _oblique_bilateral_sides()
    if picked is not None:
        try:
            _oblique_render_compare(picked[0], picked[1], origin, normal)
            return
        except Exception:  # noqa: BLE001
            traceback.print_exc()
            with state:
                state.oblique_cmp_msg = "Oblique compare render failed; showing reference only."
            state.flush()
    side = _mpr_active_side()
    if side is None:
        return
    try:
        with state:
            state.oblique_bilateral = False
        _oblique_render(side, origin, normal)
    except Exception:  # noqa: BLE001
        traceback.print_exc()


def _oblique_reset_for_side(*_a, **_k) -> None:
    """(Re)seed the plane widget at the active volume side's centre with a
    non-axis-aligned tilt, and render the initial reformat(s).

    Called on startup and whenever the active volume side / ref-tgt pair
    changes (mirrors ``_mpr_reset_for_side`` / ``_compare_reset``). A
    bare-mesh session or an unavailable volume disables the panel instead of
    touching the widget. Bilateral sessions seed the widget on the REFERENCE
    side (Mode A's side selector doubles as which bone hosts the plane) so
    the SAME plane maps onto the target via the cached registration.
    """
    picked = _oblique_bilateral_sides()
    with _LOCK:
        sides = dict(SESSION["sides"])
    if picked is not None:
        host_key = picked[0]
        side = sides.get(host_key)
    else:
        side = _mpr_active_side()
        host_key = state.mpr_side
    if side is None or side.get("arr") is None:
        with state:
            state.oblique_available = False
            state.oblique_bilateral = False
        state.flush()
        return
    info = mpr.volume_info(side["arr"], side["spacing"], side["offset_xyz"],
                           side.get("side", host_key))
    ext = info["extent_mm"]
    bounds = (ext["x"][0], ext["x"][1], ext["y"][0], ext["y"][1],
             ext["z"][0], ext["z"][1])
    center = ((ext["x"][0] + ext["x"][1]) / 2.0,
             (ext["y"][0] + ext["y"][1]) / 2.0,
             (ext["z"][0] + ext["z"][1]) / 2.0)
    # An arbitrary tilt (not axis-aligned) so the panel visibly demonstrates a
    # genuine oblique cut rather than a disguised axial/coronal/sagittal one.
    normal = np.array([0.35, 0.5, 0.79], dtype=np.float64)
    normal = normal / np.linalg.norm(normal)
    with state:
        state.oblique_side = side.get("side", host_key)
        state.oblique_window = info["default_window"]
        state.oblique_level = info["default_level"]
        state.oblique_bilateral = picked is not None
        state.oblique_cmp_msg = ""
    state.flush()

    w = OBLIQUE_WIDGET.get("widget")
    if w is None:
        # test_callback=False: we explicitly render the initial reformat(s)
        # below (on a background thread for the bilateral/heavy-registration
        # case) — letting pyvista ALSO fire the callback synchronously on
        # creation (its default) would run the registration twice on first
        # load for no benefit (same cache key -> same final entry, just
        # doubled first-load latency).
        w = PLOTTER.add_plane_widget(
            _on_oblique_widget, normal=tuple(normal), origin=center,
            bounds=bounds, implicit=True, outline_translation=False,
            test_callback=False,
        )
        OBLIQUE_WIDGET["widget"] = w
    else:
        try:
            w.PlaceWidget(bounds)
            w.SetOrigin(*center)
            w.SetNormal(*normal)
        except Exception:  # noqa: BLE001
            traceback.print_exc()

    # Render the initial reformat(s) directly (some pyvista/VTK versions do
    # not re-invoke the callback on a programmatic SetOrigin/SetNormal). A
    # bilateral registration can be SLOW on its first run (heavy ICP); run it
    # on a background thread so the UI stays responsive, exactly like
    # ``_compare_reset``. Non-bilateral rendering is fast and stays inline.
    if picked is not None:
        ref_side, tgt_side = picked

        def _job():
            with state:
                state.oblique_cmp_busy = True
                state.oblique_cmp_msg = "Registering reference <-> target… (cached after first run)"
            state.flush()
            try:
                _oblique_render_compare(ref_side, tgt_side, center, tuple(normal))
                with state:
                    state.oblique_cmp_busy = False
                    state.oblique_cmp_msg = ""
            except Exception as e:  # noqa: BLE001
                traceback.print_exc()
                with state:
                    state.oblique_cmp_busy = False
                    state.oblique_cmp_msg = f"Oblique compare registration failed: {e}"
                state.flush()

        threading.Thread(target=_job, daemon=True).start()
    else:
        _oblique_render(side, center, tuple(normal))


ctrl.oblique_reset = _oblique_reset_for_side


# --------------------------------------------------------------------------- #
# Phase IV: linked compare cross-sections.
#
# Registers reference<->target ONCE per (reference_side, target_side, params)
# and reuses the cached 4x4 affines while the crosshair moves — moving the
# crosshair must NOT re-run ICP registration every time. Gated on
# inlier_fraction >= 0.30 exactly like the API's compare-slice-map (never
# silently trust a low-overlap match — e.g. thorax-fused bone).
# --------------------------------------------------------------------------- #
_CMP_MIN_RELIABLE_INLIER = 0.30
# Cache key -> registration dict (transform, ref_world_to_tgt_world,
# tgt_world_to_ref_world, rms, inlier_fraction). Kept small (a handful of
# distinct (sides, params) combos per session), mirroring the API's cache.
_COMPARE_REG_CACHE: dict[str, dict] = {}
_COMPARE_REG_LOCK = threading.Lock()


def _compare_cache_key(ref_side: str, tgt_side: str, params: "P.Parameters",
                       manual: list | None) -> str:
    import hashlib
    sig = json.dumps(params.model_dump(), sort_keys=True, default=str)
    return hashlib.sha256(
        f"{ref_side}|{tgt_side}|{sig}|{manual}".encode()
    ).hexdigest()[:16]


def _compare_sides_available() -> tuple[str, str] | None:
    """Pick two distinct volume sides for the compare view, or None if unavailable."""
    with _LOCK:
        if SESSION.get("is_mesh"):
            return None
        sides = {k: v for k, v in SESSION["sides"].items() if v.get("arr") is not None}
    names = list(sides.keys())
    if len(names) < 2:
        return None
    ref = state.ref_side if state.ref_side in sides else names[0]
    tgt = state.tgt_side if (state.tgt_side in sides and state.tgt_side != ref) else (
        next((n for n in names if n != ref), names[0]))
    return ref, tgt


def _get_compare_registration(ref_side: str, tgt_side: str) -> dict:
    """Return the CACHED compare_registration result, computing it only on a
    cache miss (registers once, reuses the 4x4 while the crosshair moves)."""
    params = _params_from_state()
    manual = _manual_transform_matrix()
    key = _compare_cache_key(ref_side, tgt_side, params, manual)
    with _COMPARE_REG_LOCK:
        cached = _COMPARE_REG_CACHE.get(key)
    if cached is not None:
        return cached
    with _LOCK:
        ref = SESSION["sides"][ref_side]
        tgt = SESSION["sides"][tgt_side]
    reg = pipeline.compare_registration(ref, tgt, params, manual_transform=manual)
    with _COMPARE_REG_LOCK:
        _COMPARE_REG_CACHE[key] = reg
        while len(_COMPARE_REG_CACHE) > 8:
            _COMPARE_REG_CACHE.pop(next(iter(_COMPARE_REG_CACHE)))
    return reg


def _compare_render_plane(side: dict, plane: str, idx: int, window: float, level: float) -> str:
    import base64
    png = mpr.render_slice_png(side["arr"], side["spacing"], plane, idx,
                               window=window, level=level, max_dim=384)
    return "data:image/png;base64," + base64.b64encode(png).decode("ascii")


def _compare_sync_from_ref_voxel(ijk, *, reg: dict | None = None) -> None:
    """Adopt a REFERENCE voxel: render the ref panels, map through the cached
    registration to a TARGET voxel via apply_affine, then render the target
    panels at the matched (clamped) voxel. Surfaces the reliable/amber gate."""
    picked = _compare_sides_available()
    if picked is None:
        return
    ref_side, tgt_side = picked
    with _LOCK:
        ref = SESSION["sides"][ref_side]
        tgt = SESSION["sides"][tgt_side]

    ref_shape = ref["arr"].shape  # (nz, ny, nx)
    ix, iy, iz = (int(v) for v in ijk)
    ref_sl = mpr.slices_from_voxel((ix, iy, iz), ref_shape)
    ref_ix = mpr.clamp_index(ref_shape, "sagittal", ix)
    ref_iy = mpr.clamp_index(ref_shape, "coronal", iy)
    ref_iz = mpr.clamp_index(ref_shape, "axial", iz)

    if reg is None:
        reg = _get_compare_registration(ref_side, tgt_side)
    ref_world = mpr.voxel_to_world((ref_ix, ref_iy, ref_iz), ref["spacing"], ref["offset_xyz"])
    tgt_world = pipeline.apply_affine(reg["ref_world_to_tgt_world"], ref_world)
    tgt_ijk = mpr.world_to_voxel(tgt_world, tgt["spacing"], tgt["offset_xyz"])
    tgt_shape = tgt["arr"].shape
    tix, tiy, tiz = (int(v) for v in tgt_ijk)
    tgt_in_bounds = (0 <= tix < tgt_shape[2] and 0 <= tiy < tgt_shape[1] and 0 <= tiz < tgt_shape[0])
    tgt_sl = mpr.slices_from_voxel((tix, tiy, tiz), tgt_shape)

    reliable = reg["inlier_fraction"] >= _CMP_MIN_RELIABLE_INLIER
    note = ("registration is well-constrained" if reliable else
            "low overlap — the linked target slice is unreliable "
            "(isolate the bone / adjust registration first)")

    window, level = float(state.cmp_window), float(state.cmp_level)
    with state:
        state.cmp_ref_side, state.cmp_tgt_side = ref_side, tgt_side
        state.cmp_ix, state.cmp_iy, state.cmp_iz = ref_ix, ref_iy, ref_iz
        state.cmp_idx_axial = ref_sl["axial"]
        state.cmp_idx_coronal = ref_sl["coronal"]
        state.cmp_idx_sagittal = ref_sl["sagittal"]
        state.cmp_n_axial = mpr.n_slices(ref_shape, "axial")
        state.cmp_n_coronal = mpr.n_slices(ref_shape, "coronal")
        state.cmp_n_sagittal = mpr.n_slices(ref_shape, "sagittal")
        state.cmp_tgt_ix, state.cmp_tgt_iy, state.cmp_tgt_iz = tix, tiy, tiz
        state.cmp_tgt_in_bounds = tgt_in_bounds
        state.cmp_rms = round(float(reg["rms"]), 3)
        state.cmp_inlier_fraction = round(float(reg["inlier_fraction"]), 3)
        state.cmp_reliable = bool(reliable)
        state.cmp_reg_note = note
        state.cmp_ref_img_axial = _compare_render_plane(ref, "axial", ref_sl["axial"], window, level)
        state.cmp_ref_img_coronal = _compare_render_plane(ref, "coronal", ref_sl["coronal"], window, level)
        state.cmp_ref_img_sagittal = _compare_render_plane(ref, "sagittal", ref_sl["sagittal"], window, level)
        state.cmp_tgt_img_axial = _compare_render_plane(tgt, "axial", tgt_sl["axial"], window, level)
        state.cmp_tgt_img_coronal = _compare_render_plane(tgt, "coronal", tgt_sl["coronal"], window, level)
        state.cmp_tgt_img_sagittal = _compare_render_plane(tgt, "sagittal", tgt_sl["sagittal"], window, level)
    state.flush()


def _compare_reset(*_a, **_k) -> None:
    """(Re)compute availability + registration for the current ref/tgt pair and
    center the reference crosshair, exactly like _mpr_reset_for_side."""
    picked = _compare_sides_available()
    with state:
        state.compare_available = picked is not None
    state.flush()
    if picked is None:
        with state:
            state.cmp_msg = "Compare needs two distinct loaded volume sides."
        state.flush()
        return
    ref_side, tgt_side = picked

    def _job():
        with state:
            state.cmp_busy = True
            state.cmp_msg = "Registering reference <-> target… (cached after first run)"
        state.flush()
        try:
            reg = _get_compare_registration(ref_side, tgt_side)
            with _LOCK:
                ref = SESSION["sides"][ref_side]
            nz, ny, nx = ref["arr"].shape
            _compare_sync_from_ref_voxel((nx // 2, ny // 2, nz // 2), reg=reg)
            with state:
                state.cmp_busy = False
                state.cmp_msg = ""
        except Exception as e:  # noqa: BLE001
            traceback.print_exc()
            with state:
                state.cmp_busy = False
                state.cmp_msg = f"Compare registration failed: {e}"
            state.flush()

    threading.Thread(target=_job, daemon=True).start()


def _compare_on_plane_index_change(*_a, **_k) -> None:
    """A compare-panel plane slider moved: mirror into the ref crosshair voxel,
    re-map to target, and re-render both sides (reuses the cached registration)."""
    if not state.compare_available:
        return
    ijk = (int(state.cmp_idx_sagittal), int(state.cmp_idx_coronal), int(state.cmp_idx_axial))
    _compare_sync_from_ref_voxel(ijk)


def _compare_refresh_window_level(*_a, **_k) -> None:
    """Window/level changed: re-render both panel sets at the current indices
    without touching the registration or crosshair."""
    if not state.compare_available:
        return
    ijk = (int(state.cmp_ix), int(state.cmp_iy), int(state.cmp_iz))
    _compare_sync_from_ref_voxel(ijk)


def _on_pick_to_compare(point) -> None:
    """Left-click on the 3D REFERENCE surface (compare mode) -> drive the
    reference crosshair and re-map to the target side, mirroring _on_pick_to_mpr."""
    if point is None or not state.compare_active:
        return
    picked = _compare_sides_available()
    if picked is None:
        return
    ref_side, _tgt_side = picked
    with _LOCK:
        ref = SESSION["sides"][ref_side]
    try:
        ijk = mpr.world_to_voxel(np.asarray(point, dtype=float), ref["spacing"], ref["offset_xyz"])
        _compare_sync_from_ref_voxel(ijk)
    except Exception:  # noqa: BLE001
        traceback.print_exc()


def toggle_compare(*_a, **_k) -> None:
    """User toggled compare mode on: (re)compute availability + registration."""
    if state.compare_active:
        _compare_reset()


def _compare_on_ref_tgt_change(*_a, **_k) -> None:
    """A ref/tgt swap invalidates the cached registration pairing shown in the
    compare panel — only matters while compare mode is active."""
    if state.compare_active:
        _compare_reset()


ctrl.compare_reset = _compare_reset
ctrl.toggle_compare = toggle_compare

for _k in ("cmp_idx_axial", "cmp_idx_coronal", "cmp_idx_sagittal"):
    state.change(_k)(_compare_on_plane_index_change)
for _k in ("cmp_window", "cmp_level"):
    state.change(_k)(_compare_refresh_window_level)
state.change("compare_active")(toggle_compare)
for _k in ("ref_side", "tgt_side"):
    state.change(_k)(_compare_on_ref_tgt_change)


def _params_from_state() -> "P.Parameters":
    updates = {c["key"]: state[c["key"]] for c in control_specs()
               if state[c["key"]] is not None}
    return P.Parameters(**updates)


def _manual_transform_matrix() -> list[list[float]] | None:
    """Compose the operator nudge (rotations then translation) into a 4x4 list.

    Returns ``None`` when the nudge is disabled or effectively identity so the
    backend takes its untouched auto-registration path.
    """
    if not state.manual_enabled:
        return None
    tx, ty, tz = float(state.manual_tx), float(state.manual_ty), float(state.manual_tz)
    rx, ry, rz = (np.deg2rad(float(state.manual_rx)),
                  np.deg2rad(float(state.manual_ry)),
                  np.deg2rad(float(state.manual_rz)))
    if not any((tx, ty, tz, rx, ry, rz)):
        return None

    def _rot(axis: str, a: float) -> np.ndarray:
        c, s = np.cos(a), np.sin(a)
        R = np.eye(4)
        if axis == "x":
            R[1, 1], R[1, 2], R[2, 1], R[2, 2] = c, -s, s, c
        elif axis == "y":
            R[0, 0], R[0, 2], R[2, 0], R[2, 2] = c, s, -s, c
        else:  # z
            R[0, 0], R[0, 1], R[1, 0], R[1, 1] = c, -s, s, c
        return R

    M = _rot("z", rz) @ _rot("y", ry) @ _rot("x", rx)
    M[0, 3], M[1, 3], M[2, 3] = tx, ty, tz
    return M.tolist()


# --------------------------------------------------------------------------- #
# Stats / meta rendering (HTML, no overlap: simple definition rows).
# --------------------------------------------------------------------------- #
def _stat_rows(title: str, items: list[tuple[str, str]]) -> str:
    rows = "".join(
        f"<div style='display:flex;justify-content:space-between;gap:12px;"
        f"padding:1px 0;font-size:12px;line-height:1.5'>"
        f"<span style='color:#555'>{k}</span>"
        f"<span style='font-variant-numeric:tabular-nums;font-weight:600'>{v}</span></div>"
        for k, v in items
    )
    return (f"<div style='margin-bottom:8px'>"
            f"<div style='font-size:11px;font-weight:700;letter-spacing:.04em;"
            f"text-transform:uppercase;color:#333;margin-bottom:2px'>{title}</div>"
            f"{rows}</div>")


def _meta_html() -> str:
    m = SESSION.get("meta") or {}
    if not m:
        return "<div style='font-size:12px;color:#888'>No scan loaded.</div>"
    if SESSION.get("is_mesh"):
        items = [
            ("Kind", "Surface mesh"),
            ("Format", str(m.get("format", "—"))),
            ("Points", f"{m.get('n_points', 0):,}"),
        ]
        return _stat_rows("Loaded mesh", items)
    items = [
        ("Series", str(m.get("series", "—"))),
        ("Shape (z,y,x)", "×".join(str(s) for s in m.get("shape", []))),
        ("Spacing (mm)", "×".join(str(s) for s in m.get("spacing_mm", []))),
        ("Laterality", str(m.get("laterality", "—"))),
    ]
    return _stat_rows("Loaded scan", items)


# --------------------------------------------------------------------------- #
# Histogram + clip / visible-part stats.
#
# Both features are DISPLAY-ONLY: they read the scalar array already sitting on
# the LAST COMPUTED mesh (``_LAST_MESH``) — the same mesh the 3D view and the
# hover tooltip use — and never touch core.pipeline's thickness/deviation
# recompute. Every number comes straight from that mesh's point_data; nothing
# is fabricated.
# --------------------------------------------------------------------------- #
def _active_scalar_mesh():
    """Return (mesh, scalar_key, label) for whatever is CURRENTLY displayed."""
    diverging = state.mode == "B" and state.b_view == "deviation"
    mesh = _LAST_MESH["deviation"] if diverging else _LAST_MESH["thickness"]
    key = "deviation_mm" if diverging else "thickness_mm"
    label = "Signed deviation (mm)" if diverging else "Cortical thickness (mm)"
    return mesh, key, label


def _scalar_stats(v: np.ndarray) -> dict:
    """Same shape as core.pipeline._stats (mean/median/sd/min/max/n) — kept
    local because this is a DISPLAY-only recompute over a client-side subset
    (the clipped mesh), not a new measurement pipeline."""
    v = np.asarray(v, dtype=np.float64)
    v = v[np.isfinite(v)]
    if v.size == 0:
        return {"mean": float("nan"), "median": float("nan"), "sd": float("nan"),
                "min": float("nan"), "max": float("nan"), "n": 0}
    return {
        "mean": round(float(np.mean(v)), 3), "median": round(float(np.median(v)), 3),
        "sd": round(float(np.std(v)), 3), "min": round(float(np.min(v)), 3),
        "max": round(float(np.max(v)), 3), "n": int(v.size),
    }


def _histogram_bins(values: np.ndarray, n_bins: int = 24) -> dict:
    """Bin edges/counts for the active scalar (finite values only). Exposed as
    plain data (not just a picture) so callers/tests can verify honesty:
    ``sum(counts) == number of finite vertices``."""
    v = np.asarray(values, dtype=np.float64)
    v = v[np.isfinite(v)]
    if v.size == 0:
        return {"counts": [], "edges": [], "n": 0}
    counts, edges = np.histogram(v, bins=n_bins)
    return {"counts": [int(c) for c in counts], "edges": [float(e) for e in edges],
            "n": int(v.size)}


def _render_histogram_png(values: np.ndarray, label: str, *, highlight: np.ndarray | None = None) -> str:
    """Render a small matplotlib histogram of ``values`` to a base64 PNG data
    URI. When ``highlight`` (the visible/clipped subset) is given, it is
    overlaid so the operator can see the visible part's distribution against
    the whole map's."""
    import base64
    import io

    import matplotlib
    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    v = np.asarray(values, dtype=np.float64)
    v = v[np.isfinite(v)]
    fig, ax = plt.subplots(figsize=(3.6, 2.0), dpi=120)
    if v.size:
        ax.hist(v, bins=24, color="#3b6ea5", alpha=0.85, label="total")
        if highlight is not None:
            h = np.asarray(highlight, dtype=np.float64)
            h = h[np.isfinite(h)]
            if h.size:
                ax.hist(h, bins=24, color="#e8a33d", alpha=0.65, label="visible")
                ax.legend(fontsize=6, frameon=False)
    ax.set_xlabel(label, fontsize=8)
    ax.set_ylabel("vertices", fontsize=8)
    ax.tick_params(labelsize=7)
    fig.tight_layout()
    buf = io.BytesIO()
    fig.savefig(buf, format="png", facecolor="white")
    plt.close(fig)
    return "data:image/png;base64," + base64.b64encode(buf.getvalue()).decode("ascii")


def _clip_mesh(mesh, axis: str, fraction: float, invert: bool):
    """Clip ``mesh`` with an axis-aligned plane at ``fraction`` (0..1) along
    that axis' bounding-box extent, keeping the ``invert``-selected side.

    Uses ``pyvista.PolyData.clip`` (a real geometric clip, not a scalar
    threshold), so it isolates a sub-PART of the surface — the clipped mesh
    keeps its original point_data arrays (thickness_mm / deviation_mm / the
    Mode-B extras), which is what makes the "visible part" stats honest: they
    are computed from THIS clipped mesh's own scalars, not re-derived.
    """
    bounds = mesh.bounds  # (xmin, xmax, ymin, ymax, zmin, zmax)
    axis_idx = {"x": 0, "y": 1, "z": 2}[axis]
    lo, hi = bounds[axis_idx * 2], bounds[axis_idx * 2 + 1]
    origin = [ (bounds[0] + bounds[1]) / 2.0, (bounds[2] + bounds[3]) / 2.0,
              (bounds[4] + bounds[5]) / 2.0 ]
    origin[axis_idx] = lo + fraction * (hi - lo)
    normal = [0.0, 0.0, 0.0]
    normal[axis_idx] = 1.0 if invert else -1.0
    return mesh.clip(normal=tuple(normal), origin=tuple(origin), invert=False)


def refresh_histogram_and_clip(*_a, **_k) -> None:
    """Recompute the histogram + (optional) clip/visible-part stats from the
    CURRENTLY DISPLAYED mesh's own point data. Display-only: runs entirely on
    the last computed mesh, never calls core.pipeline. Safe to call whenever a
    clip knob, the mode/b_view, or a fresh compute changes."""
    mesh, key, label = _active_scalar_mesh()
    if mesh is None or key not in mesh.point_data:
        with state:
            state.histogram_img = ""
            state.histogram_bins = {"counts": [], "edges": [], "n": 0}
            state.clip_total_stats = {}
            state.clip_visible_stats = {}
            state.clip_msg = "Nothing computed yet."
        state.flush()
        return

    total_vals = np.asarray(mesh.point_data[key], dtype=np.float64)
    total_stats = _scalar_stats(total_vals)

    visible_vals = total_vals
    visible_stats = total_stats
    clip_msg = ""
    if state.clip_enabled:
        try:
            clipped = _clip_mesh(mesh, state.clip_axis, float(state.clip_fraction),
                                 bool(state.clip_invert))
            if clipped.n_points > 0 and key in clipped.point_data:
                visible_vals = np.asarray(clipped.point_data[key], dtype=np.float64)
                visible_stats = _scalar_stats(visible_vals)
                clip_msg = (f"{visible_stats['n']:,} / {total_stats['n']:,} vertices "
                           f"visible after clip.")
            else:
                visible_vals = np.array([])
                visible_stats = _scalar_stats(visible_vals)
                clip_msg = "Clip removed all vertices — widen the range."
        except Exception as e:  # noqa: BLE001
            traceback.print_exc()
            clip_msg = f"Clip failed: {e}"
            visible_vals, visible_stats = total_vals, total_stats

    hist_highlight = visible_vals if state.clip_enabled else None
    with state:
        state.histogram_img = _render_histogram_png(total_vals, label, highlight=hist_highlight)
        state.histogram_bins = _histogram_bins(total_vals)
        state.clip_total_stats = total_stats
        state.clip_visible_stats = visible_stats
        state.clip_msg = clip_msg
    state.flush()


ctrl.refresh_histogram_and_clip = refresh_histogram_and_clip


# --------------------------------------------------------------------------- #
# Statistics & Figures panel (publication-style PNG figures).
#
# DISPLAY-ONLY, same contract as the histogram above: reads the CURRENTLY
# COMPUTED mesh's own scalar array (``_LAST_MESH`` / ``_LAST_REGIONS``) and
# renders through ``core.stats.figures.render_result_figures`` — the exact
# module the API's POST /session/{sid}/figures uses — so a trame render and an
# API render of the same scalar array are byte-identical at a given DPI.
# Never re-runs core.pipeline. Mode B (deviation) has one registered surface,
# so "by_region" is naturally omitted there (regions=None below).
# --------------------------------------------------------------------------- #
def refresh_stats_figures(*_a, **_k) -> None:
    mesh, key, _label = _active_scalar_mesh()
    if mesh is None or key not in mesh.point_data:
        with state:
            state.stats_figures = {}
            state.stats_figures_note = ""
            state.stats_descriptive = {}
        state.flush()
        return

    values = np.asarray(mesh.point_data[key], dtype=np.float64)
    diverging = state.mode == "B" and state.b_view == "deviation"
    regions = None if diverging else _LAST_REGIONS

    try:
        raw = render_result_figures(scalar_values=values, scalar_name=key,
                                    regions=regions, dpi=150)
        encoded = {name: "data:image/png;base64," + _b64(png) for name, png in raw.items()}
        note = ("Single-subject descriptive statistics — distribution and "
                "per-region summaries for this scan only; not a group "
                "comparison and not for diagnostic use.")
        if not diverging and (not regions or len(regions) < 2) and "by_region" not in raw:
            note += (" 'By-region' omitted: fewer than 2 bone regions were "
                    "segmented — nothing to compare.")
        elif diverging:
            note += (" 'By-region' omitted: Mode B has one registered surface "
                    "(no per-region breakdown).")
        # Descriptive stat block (percentiles / IQR / %>1mm / %>2mm) — same
        # numbers the API's /figures endpoint returns and the Table-1 figure shows.
        stats_block = descriptive_stats(values, scalar_name=key)
        with state:
            state.stats_figures = encoded
            state.stats_figures_note = note
            state.stats_descriptive = stats_block
        state.flush()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.stats_figures = {}
            state.stats_figures_note = f"Figures failed: {e}"
            state.stats_descriptive = {}
        state.flush()


def _b64(data: bytes) -> str:
    import base64
    return base64.b64encode(data).decode("ascii")


ctrl.refresh_stats_figures = refresh_stats_figures


def _figures_export_worker():
    try:
        mesh, key, _label = _active_scalar_mesh()
        if mesh is None or key not in mesh.point_data:
            raise RuntimeError("Nothing computed yet — run a compute first.")
        values = np.asarray(mesh.point_data[key], dtype=np.float64)
        diverging = state.mode == "B" and state.b_view == "deviation"
        regions = None if diverging else _LAST_REGIONS

        formats = [f.lower() for f in (state.figures_export_formats or [])]
        if not formats:
            raise RuntimeError("Pick at least one export format.")
        dpi = int(state.figures_export_dpi)
        if dpi <= 0:
            raise RuntimeError("DPI must be positive.")

        gen_key = uuid.uuid4().hex[:12]
        out_dir = EXPORTS_DIR / "figures" / gen_key
        out_dir.mkdir(parents=True, exist_ok=True)

        links = []
        for fmt in formats:
            raw = render_result_figures(scalar_values=values, scalar_name=key,
                                        regions=regions, fmt=fmt, dpi=dpi)
            for name, data in raw.items():
                fname = f"{name}.{fmt}"
                (out_dir / fname).write_bytes(data)
                links.append({"name": name, "fmt": fmt,
                             "url": f"/downloads/figures/{gen_key}/{fname}"})

        if not links:
            raise RuntimeError("No figures available for the current result.")

        with state:
            state.figures_export_links = links
            state.figures_export_busy = False
            state.figures_export_msg = f"Exported {len(links)} file(s)."
        state.flush()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.figures_export_busy = False
            state.figures_export_msg = f"Export failed: {e}"
            state.figures_export_links = []
        state.flush()


def do_export_figures(*_a, **_k):
    if state.figures_export_busy:
        return
    with state:
        state.figures_export_busy = True
        state.figures_export_msg = "Exporting…"
        state.figures_export_links = []
    state.flush()
    threading.Thread(target=_figures_export_worker, daemon=True).start()


ctrl.do_export_figures = do_export_figures


# --------------------------------------------------------------------------- #
# Hover picking: read the scalar(s) at the point under the cursor.
#
# Mode A / Mode-B-thickness: single "thickness_mm" readout (unchanged).
# Mode B deviation: the reference mesh returned by core.pipeline.compare_sides
# carries FOUR per-vertex arrays (deviation_mm, ref_thickness_mm,
# tgt_thickness_mm, thickness_diff_mm — see hover_scalars in the pipeline
# result). We read all four at the picked vertex id so the tooltip surfaces
# reference thickness, target (contralateral) thickness, their difference, AND
# the signed deviation — every number sourced straight from the loaded mesh's
# point data, never fabricated.
# --------------------------------------------------------------------------- #
_MODE_B_HOVER_SCALARS = ["deviation_mm", "ref_thickness_mm", "tgt_thickness_mm",
                        "thickness_diff_mm"]
_HOVER_LABELS = {
    "deviation_mm": ("Deviation", "%+.2f"),
    "ref_thickness_mm": ("Reference thickness", "%.2f"),
    "tgt_thickness_mm": ("Target thickness", "%.2f"),
    "thickness_diff_mm": ("Thickness diff (ref − tgt)", "%+.2f"),
}


def _read_hover_scalars(mesh, pid: int, keys: list[str]) -> dict[str, dict]:
    """Read each of ``keys`` at vertex ``pid`` (best-effort per key: an array
    that isn't present or is NaN at that vertex is simply omitted — never
    fabricated). Returns {key: {value, mean}}."""
    out: dict[str, dict] = {}
    for key in keys:
        if key not in mesh.point_data:
            continue
        arr = np.asarray(mesh.point_data[key], dtype=float)
        val = float(arr[pid])
        if not np.isfinite(val):
            continue
        finite = arr[np.isfinite(arr)]
        mean = float(np.mean(finite)) if finite.size else float("nan")
        out[key] = {"value": val, "mean": mean}
    return out


def _on_hover(point, *_a, **_k):
    """pyvista hover callback: show the picked scalar(s) + position in a tooltip.

    ``point`` is the world-space (x,y,z) under the cursor (or None off-surface).
    We look up the active surface's scalar(s) there and compare each to its map
    mean. In Mode B deviation, ALL FOUR carried scalars are read from the SAME
    picked vertex (registered surfaces share vertex indexing per-point).
    """
    mode_b_dev = state.mode == "B" and state.b_view == "deviation"
    mesh = _LAST_MESH["deviation"] if mode_b_dev else _LAST_MESH["thickness"]
    primary_key = "deviation_mm" if mode_b_dev else "thickness_mm"
    if point is None or mesh is None or primary_key not in mesh.point_data:
        with state:
            state.hover_active = False
        state.flush()
        return
    try:
        pid = mesh.find_closest_point(np.asarray(point, dtype=float))
        pos = np.asarray(mesh.points[pid], dtype=float)
        keys = _MODE_B_HOVER_SCALARS if mode_b_dev else [primary_key]
        readings = _read_hover_scalars(mesh, pid, keys)
    except Exception:  # noqa: BLE001
        return
    if not readings:
        return

    lines = []
    for key in keys:
        r = readings.get(key)
        if r is None:
            continue
        label, fmt = _HOVER_LABELS.get(key, (key, "%.2f"))
        delta = r["value"] - r["mean"]
        lines.append(
            f"<div style='margin-bottom:2px'>"
            f"<span style='font-weight:700'>{label}:</span> "
            f"{fmt % r['value']} mm "
            f"<span style='color:#aaa'>(map mean {fmt % r['mean']}, "
            f"{'+' if delta >= 0 else ''}{delta:.2f})</span></div>"
        )
    html_out = (
        "".join(lines) +
        f"<div style='font-size:11px;color:#ddd;line-height:1.5;margin-top:2px'>"
        f"x {pos[0]:.1f} · y {pos[1]:.1f} · z {pos[2]:.1f} mm</div>"
    )
    with state:
        state.hover_html = html_out
        state.hover_active = True
    state.flush()


def _on_pick_to_mpr(point, *_a, **_k):
    """Left-click on the 3D surface -> drive the MPR crosshair (and, when compare
    mode is active, the linked compare crosshair too).

    Mirrors the API's /pick-to-slices: world (x,y,z) mm -> world_to_voxel (with the
    active side's offset) -> slices_from_voxel -> the three 2D panels re-render at
    the picked voxel. Off-surface clicks (point is None) are ignored.
    """
    if point is None:
        return
    if state.compare_active:
        _on_pick_to_compare(point)
        return
    side = _mpr_active_side()
    if side is None:
        return
    try:
        ijk = mpr.world_to_voxel(np.asarray(point, dtype=float), side["spacing"],
                                 side["offset_xyz"])
        _mpr_sync_from_voxel(ijk)
    except Exception:  # noqa: BLE001
        traceback.print_exc()


def _enable_hover() -> None:
    """(Re)attach the hover-pick (tooltip) and left-click-pick (MPR crosshair)
    callbacks to the current plotter surface.

    Hover reads the scalar under the cursor (tooltip); a left click drives the MPR
    crosshair via world_to_voxel + slices_from_voxel (byte-identical to the API's
    pick-to-slices). Both are best-effort — the rest of the UI works without them.
    """
    try:
        PLOTTER.disable_picking()
    except Exception:  # noqa: BLE001
        pass
    try:
        PLOTTER.enable_point_picking(
            callback=_on_hover, show_message=False, show_point=False,
            use_picker="hardware", left_clicking=False, picker="point",
        )
    except Exception:  # noqa: BLE001
        # Hover picking is best-effort; the rest of the UI works without it.
        pass
    try:
        # A separate surface-point pick on left click updates the MPR crosshair.
        PLOTTER.enable_surface_point_picking(
            callback=_on_pick_to_mpr, show_message=False, show_point=False,
            left_clicking=True,
        )
    except Exception:  # noqa: BLE001
        # Click-to-MPR is best-effort; sliders still drive the crosshair.
        pass


# --------------------------------------------------------------------------- #
# Realtime auto-recompute plumbing.
#
# Every change to a recompute=True parameter (or to side / mode / b_view /
# reference / target / mirror / manual-anchor) SCHEDULES a debounced background
# recompute — the user never has to click Apply. Rapid changes (e.g. dragging a
# slider) are coalesced: we (re)arm a ~600 ms timer and only the final change
# fires. A monotonically increasing request id supersedes older computes so a
# slow, stale result can never overwrite a newer one (the AbortController
# analogue for a server-side app).
# --------------------------------------------------------------------------- #
RECOMPUTE_DEBOUNCE_S = 0.6

_REQ_LOCK = threading.Lock()
_REQ_COUNTER = 0          # latest scheduled request id (monotonic)
_DEBOUNCE_TIMER: threading.Timer | None = None


def _next_request_id() -> int:
    """Reserve a fresh, strictly-increasing request id (supersedes older ones)."""
    global _REQ_COUNTER
    with _REQ_LOCK:
        _REQ_COUNTER += 1
        return _REQ_COUNTER


def _is_current(req_id: int) -> bool:
    """True while ``req_id`` is still the newest scheduled compute."""
    with _REQ_LOCK:
        return req_id == _REQ_COUNTER


# --------------------------------------------------------------------------- #
# Compute (runs on a background thread).
# --------------------------------------------------------------------------- #
def _compute_worker(req_id: int | None = None):
    # A stale request (superseded before it even started) is dropped.
    if req_id is not None and not _is_current(req_id):
        return
    try:
        params = _params_from_state()
        with _LOCK:
            sides = dict(SESSION["sides"])
            is_mesh_sess = bool(SESSION["is_mesh"])
        if not sides:
            raise RuntimeError("No scan loaded.")

        mode = state.mode
        wants_thickness = mode == "A" or (mode == "B" and state.b_view == "thickness")

        if wants_thickness:
            if is_mesh_sess:
                raise RuntimeError(
                    "This is a surface mesh — thickness needs a volume. "
                    "Use Mode B deviation instead.")
            side_key = state.side
            global _LAST_REGIONS
            if side_key == "both":
                # Bilateral "Both": compute LEFT + RIGHT (whole bone each) and
                # render the two thickness meshes together. The primary (left)
                # drives the stats / histogram / figures exactly like a single
                # side; the right is the second mesh in the scene.
                left = sides.get("left")
                right = sides.get("right")
                if left is None or right is None:
                    raise RuntimeError("Both view needs a left and a right side.")
                res = pipeline.analyze_thickness(
                    left["arr"], left["spacing"], params,
                    offset_xyz=left["offset_xyz"],
                )
                res_r = pipeline.analyze_thickness(
                    right["arr"], right["spacing"], params,
                    offset_xyz=right["offset_xyz"],
                )
                _LAST_MESH["thickness"] = res["mesh"]
                _LAST_MESH["thickness_second"] = res_r["mesh"]
                _LAST_REGIONS = res.get("regions")
                build_thickness_scene(PLOTTER, res["mesh"], params=params,
                                      side_label="Left + Right",
                                      second_mesh=res_r["mesh"])
                s = res["stats"]
                sr = res_r["stats"]
                html_out = _meta_html() + _stat_rows(
                    "Thickness — Left (mm)",
                    [("mean", f"{s['mean']:.3f}"), ("median", f"{s['median']:.3f}"),
                     ("sd", f"{s['sd']:.3f}"), ("min", f"{s['min']:.3f}"),
                     ("max", f"{s['max']:.3f}"), ("n vertices", f"{s['n']:,}")],
                ) + _stat_rows(
                    "Thickness — Right (mm)",
                    [("mean", f"{sr['mean']:.3f}"), ("median", f"{sr['median']:.3f}"),
                     ("sd", f"{sr['sd']:.3f}"), ("min", f"{sr['min']:.3f}"),
                     ("max", f"{sr['max']:.3f}"), ("n vertices", f"{sr['n']:,}")],
                )
            else:
                side = sides.get(side_key)
                if side is None:
                    raise RuntimeError(f"Unknown side '{side_key}'.")
                region_label = state.region_label
                try:
                    region_label = int(region_label) if region_label is not None else None
                except (TypeError, ValueError):
                    region_label = None
                res = pipeline.analyze_thickness(
                    side["arr"], side["spacing"], params,
                    region_label=region_label, offset_xyz=side["offset_xyz"],
                )
                _LAST_MESH["thickness"] = res["mesh"]
                _LAST_MESH["thickness_second"] = None  # single-side: no second bone
                _LAST_REGIONS = res.get("regions")
                # Adopt the server's chosen region so the picker reflects reality,
                # WITHOUT re-triggering a recompute (only change when it differs).
                picked = res.get("region_label")
                if picked is not None and state.region_label != picked:
                    state.region_label = picked
                build_thickness_scene(PLOTTER, res["mesh"], params=params,
                                      side_label=_side_label(side_key))
                s = res["stats"]
                html_out = _meta_html() + _stat_rows(
                    f"Thickness — {_side_label(side_key)} (mm)",
                    [("mean", f"{s['mean']:.3f}"), ("median", f"{s['median']:.3f}"),
                     ("sd", f"{s['sd']:.3f}"), ("min", f"{s['min']:.3f}"),
                     ("max", f"{s['max']:.3f}"), ("n vertices", f"{s['n']:,}")],
                ) + _stat_rows("Segmentation",
                               [("region label", str(res["region_label"])),
                                ("metal fraction", f"{res['metal_fraction']:.4f}")])
        else:  # Mode B deviation
            ref = sides.get(state.ref_side)
            tgt = sides.get(state.tgt_side)
            if ref is None or tgt is None:
                raise RuntimeError("Reference/target side unknown.")
            if state.ref_side == state.tgt_side:
                raise RuntimeError("Choose two different sides for deviation.")
            manual = _manual_transform_matrix()
            res = pipeline.compare_sides(ref, tgt, params, manual_transform=manual)
            _LAST_MESH["deviation"] = res["mesh"]
            build_deviation_scene(PLOTTER, res["mesh"], params=params)
            st = res["stats"]
            reg = res["registration"]
            html_out = _meta_html() + _stat_rows(
                "Registration",
                [("RMS (mm)", f"{reg['rms']:.3f}"),
                 ("inlier fraction", f"{reg['inlier_fraction']:.3f}"),
                 ("manual nudge", "yes" if reg.get("manual_adjusted") else "no"),
                 ("reference", _side_label(state.ref_side)),
                 ("target", _side_label(state.tgt_side))],
            ) + _stat_rows(
                "Signed deviation (mm)",
                [("mean", f"{st['mean']:.3f}"), ("median", f"{st['median']:.3f}"),
                 ("sd", f"{st['sd']:.3f}"),
                 ("max +", f"{st['max_positive']:.3f}"),
                 ("max −", f"{st['max_negative']:.3f}"),
                 ("added vol (cc)", f"{st['added_volume_cc']:.2f}"),
                 ("removed vol (cc)", f"{st['removed_volume_cc']:.2f}")],
            )

        # SUPERSEDE guard: if a newer change landed while this compute ran, drop
        # our result silently — the newer request owns the viewport now.
        if req_id is not None and not _is_current(req_id):
            return

        _enable_hover()
        with state:
            state.stats_html = html_out
            state.status = "done"
            state.status_msg = "Recompute complete."
        if ctrl.view_update:
            ctrl.view_update()
        state.flush()
        # Fresh geometry -> refresh the histogram + clip/visible-part stats
        # from the newly computed mesh's own scalar (display-only).
        refresh_histogram_and_clip()
        # Statistics & Figures panel: publication-style PNGs from the SAME
        # newly computed mesh's scalar (display-only, no recompute).
        refresh_stats_figures()

        # After the first thickness compute for the active side, lazily load the
        # per-region preview thumbnails (cached per session/side). Skipped for
        # the deviation view and mesh sessions inside the loader.
        if wants_thickness:
            load_region_thumbnails()
    except Exception as e:  # noqa: BLE001
        # Don't surface an error from a compute that has already been superseded.
        if req_id is not None and not _is_current(req_id):
            return
        traceback.print_exc()
        with state:
            state.status = "error"
            state.status_msg = f"Compute failed: {e}"
        state.flush()


def _side_label(name: str) -> str:
    return {"left": "Left", "right": "Right", "full": "Full",
            "mesh": "Mesh"}.get(name, name.capitalize())


def _computing_msg() -> str:
    return ("Computing… (Mode B deviation involves registration and can take a "
            "while)" if (state.mode == "B" and state.b_view == "deviation")
            else "Computing…")


def recompute(*_a, **_k):
    """Kick off a background recompute NOW with the CURRENT params/mode/side.

    Bumps the request id so any in-flight/pending compute is superseded — the
    UI never stalls and an older result can't overwrite this one. Used both by
    the manual "Apply / Recompute" button and by the debounced auto path.
    """
    req_id = _next_request_id()
    with state:
        state.status = "computing"
        state.status_msg = _computing_msg()
    state.flush()
    threading.Thread(target=_compute_worker, args=(req_id,), daemon=True).start()


def schedule_recompute(*_a, **_k):
    """Debounced auto-recompute: coalesce rapid changes into ONE compute.

    Re-arms a ~600 ms timer on every call; only the last change in a burst
    actually fires ``recompute``. A "computing…" status is shown immediately so
    the user sees the pending state while they keep dragging. Coloring stays
    instant during the wait because display-only knobs never route here.
    """
    global _DEBOUNCE_TIMER
    if not SESSION.get("sides"):
        return  # nothing loaded yet; nothing to compute
    with _REQ_LOCK:
        if _DEBOUNCE_TIMER is not None:
            _DEBOUNCE_TIMER.cancel()
        _DEBOUNCE_TIMER = threading.Timer(RECOMPUTE_DEBOUNCE_S, recompute)
        _DEBOUNCE_TIMER.daemon = True
        _DEBOUNCE_TIMER.start()
    # Show the pending indicator right away (non-blocking; UI stays interactive).
    if state.status != "computing":
        with state:
            state.status = "computing"
            state.status_msg = _computing_msg()
        state.flush()


ctrl.recompute = recompute
ctrl.schedule_recompute = schedule_recompute


# --------------------------------------------------------------------------- #
# Instant DISPLAY-ONLY re-render (no server recompute).
#
# Colormap / range / colorbar-steps / reverse / center / |range| / view changes
# only affect how the EXISTING geometry is colored or framed. We re-run the
# pyvista scene builder on the LAST computed mesh with the new params — updating
# the LUT / scalar-bar / camera in place — without touching the pipeline. This
# stays instant even while a recompute is running in the background.
# --------------------------------------------------------------------------- #
def apply_display_only(*_a, **_k):
    """Recolor the current surface from the last mesh using the live params."""
    params = _params_from_state()
    diverging = state.mode == "B" and state.b_view == "deviation"
    mesh = _LAST_MESH["deviation"] if diverging else _LAST_MESH["thickness"]
    if mesh is None:
        return  # nothing rendered yet; the next compute will pick up the params
    try:
        if diverging:
            build_deviation_scene(PLOTTER, mesh, params=params)
        elif state.side == "both":
            build_thickness_scene(PLOTTER, mesh, params=params,
                                  side_label="Left + Right",
                                  second_mesh=_LAST_MESH["thickness_second"])
        else:
            build_thickness_scene(PLOTTER, mesh, params=params,
                                  side_label=_side_label(state.side))
        _enable_hover()
        if ctrl.view_update:
            ctrl.view_update()
    except Exception:  # noqa: BLE001
        traceback.print_exc()


ctrl.apply_display_only = apply_display_only


# --------------------------------------------------------------------------- #
# Wire realtime reactivity: bind every control to the right path so ANY change
# reflects automatically — no Apply click required.
#
#   * recompute=True params  -> debounced background recompute (superseding)
#   * display-only params    -> instant client-side recolor/reframe (no compute)
#   * session selectors       -> recompute (side/mode/b_view/ref/tgt)
#   * manual-anchor knobs     -> recompute (only bite when manual_enabled)
#
# Parity is preserved: which params are display-only vs recompute comes straight
# from the registry (``P.DISPLAY_ONLY_KEYS`` / the ``recompute`` flag the API
# also serves), so the two frontends agree on the classification.
# --------------------------------------------------------------------------- #
_RECOMPUTE_PARAM_KEYS = [c["key"] for c in control_specs() if c["recompute"]]
_DISPLAY_ONLY_PARAM_KEYS = [c["key"] for c in control_specs() if not c["recompute"]]
# Non-registry selectors / knobs that also require a fresh pipeline run.
_RECOMPUTE_STATE_KEYS = [
    "side", "mode", "b_view", "ref_side", "tgt_side",
    "manual_enabled", "manual_tx", "manual_ty", "manual_tz",
    "manual_rx", "manual_ry", "manual_rz",
]

for _k in _RECOMPUTE_PARAM_KEYS + _RECOMPUTE_STATE_KEYS:
    state.change(_k)(schedule_recompute)
for _k in _DISPLAY_ONLY_PARAM_KEYS:
    state.change(_k)(apply_display_only)

# Histogram + clip reactivity: purely DISPLAY-only over the last computed mesh
# — never routes through schedule_recompute/core.pipeline. Also re-run after a
# display-only recolor no-op call so switching Mode A<->B thickness view stays
# in sync even when the underlying mesh didn't change.
for _k in ("clip_enabled", "clip_axis", "clip_fraction", "clip_invert"):
    state.change(_k)(refresh_histogram_and_clip)

# MPR reactivity: a plane slider moves -> mirror to crosshair + re-render;
# window/level changes -> re-render all three panels. These are display-only for
# the 2D panels and never touch the 3D pipeline (no recompute).
for _k in ("mpr_idx_axial", "mpr_idx_coronal", "mpr_idx_sagittal"):
    state.change(_k)(_mpr_on_plane_index_change)
for _k in ("mpr_window", "mpr_level"):
    state.change(_k)(_mpr_refresh_images)
# Switching the thickness side re-points the MPR viewer at that volume.
state.change("side")(_mpr_reset_for_side)


def _oblique_refresh_window_level(*_a, **_k) -> None:
    """Window/level/size changed: re-render the reformat(s) at the CURRENT
    widget (origin, normal) without touching the plane or the pipeline."""
    if not state.oblique_available:
        return
    origin, normal = tuple(state.oblique_origin), tuple(state.oblique_normal)
    if state.oblique_bilateral:
        picked = _oblique_bilateral_sides()
        if picked is None:
            return
        try:
            _oblique_render_compare(picked[0], picked[1], origin, normal)
        except Exception:  # noqa: BLE001
            traceback.print_exc()
        return
    side = _mpr_active_side()
    if side is None:
        return
    _oblique_render(side, origin, normal)


for _k in ("oblique_window", "oblique_level", "oblique_size_mm"):
    state.change(_k)(_oblique_refresh_window_level)
# Switching the thickness side also re-seeds the oblique plane widget.
state.change("side")(_oblique_reset_for_side)


def _oblique_on_ref_tgt_change(*_a, **_k) -> None:
    """A ref/tgt swap changes which bones the oblique-compare boxes show —
    re-seed the widget on the (possibly new) reference side, exactly like a
    side switch. Only matters when oblique mode is showing (or can show) the
    bilateral pair; harmless no-op otherwise."""
    _oblique_reset_for_side()


for _k in ("ref_side", "tgt_side"):
    state.change(_k)(_oblique_on_ref_tgt_change)


# --------------------------------------------------------------------------- #
# Export: build a multi-format bundle via core.export.export_bundle and expose
# each result as a real download link served from /downloads.
# --------------------------------------------------------------------------- #
def _camera_from_state() -> dict:
    return {
        "azimuth": float(state.cam_azimuth),
        "elevation": float(state.cam_elevation),
        "roll": float(state.cam_roll),
        "zoom": float(state.cam_zoom),
    }


def _export_worker():
    try:
        params = _params_from_state()
        with _LOCK:
            sides = dict(SESSION["sides"])
            is_mesh_sess = bool(SESSION["is_mesh"])
        formats = list(state.export_formats or [])
        if not formats:
            raise RuntimeError("Pick at least one export format.")
        dpi = int(state.export_dpi)
        if dpi <= 0:
            raise RuntimeError("DPI must be positive.")

        mode = state.mode
        diverging = mode == "B" and state.b_view == "deviation"
        if diverging:
            ref = sides.get(state.ref_side)
            tgt = sides.get(state.tgt_side)
            if ref is None or tgt is None or state.ref_side == state.tgt_side:
                raise RuntimeError("Mode B export needs two distinct sides.")
            res = pipeline.compare_sides(ref, tgt, params,
                                         manual_transform=_manual_transform_matrix())
            mesh, scalar = res["mesh"], res["scalar"]
        else:
            if is_mesh_sess:
                raise RuntimeError(
                    "Thickness export needs a volume; this is a surface mesh.")
            # The raster/mesh bundle renders ONE surface; in the bilateral 'both'
            # view we export the primary (left) side.
            side_key = "left" if state.side == "both" else state.side
            side = sides.get(side_key)
            if side is None:
                raise RuntimeError(f"Unknown side '{side_key}'.")
            res = pipeline.analyze_thickness(side["arr"], side["spacing"], params,
                                             offset_xyz=side["offset_xyz"])
            mesh, scalar = res["mesh"], "thickness_mm"

        # Fig-2 measurement overlays (raster/DICOM only) — auto-placed. Only
        # meaningful for the thickness surface, mirroring React's annotateApplies.
        annotate = None
        if not diverging and (state.annotate_line or state.annotate_height):
            annotate = {}
            if state.annotate_line:
                annotate["sampling_line"] = True
            if state.annotate_height:
                annotate["height"] = True

        key = uuid.uuid4().hex[:12]
        out_dir = EXPORTS_DIR / key
        files = export_bundle(mesh, scalar, params, out_dir,
                              formats=tuple(f.lower() for f in formats),
                              dpi=dpi, camera=_camera_from_state(),
                              diverging=diverging, stem="export", annotate=annotate)
        links = [{"fmt": fmt, "url": f"/downloads/{key}/{Path(p).name}"}
                 for fmt, p in files.items()]
        with state:
            state.export_links = links
            state.export_busy = False
            state.export_msg = f"Exported {len(links)} file(s)."
        state.flush()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.export_busy = False
            state.export_msg = f"Export failed: {e}"
            state.export_links = []
        state.flush()


def do_export(*_a, **_k):
    if state.export_busy:
        return
    with state:
        state.export_busy = True
        state.export_msg = "Exporting…"
        state.export_links = []
    state.flush()
    threading.Thread(target=_export_worker, daemon=True).start()


ctrl.do_export = do_export


# --------------------------------------------------------------------------- #
# Phase V: AR asset export (GLB).
#
# Exports the CURRENTLY DISPLAYED surface (Mode A thickness, or Mode B
# deviation) via core.export.mesh.export_mesh(..., fmt='glb') with the active
# colormap/clim baked into per-vertex colour, and serves it from /downloads so
# a real download link works from the running UI. GLB opens directly in a
# phone's AR viewer (Android Scene Viewer / a desktop 3D viewer); genuine iOS AR
# Quick Look needs a USDZ, which this app does NOT generate — the caption says
# so rather than overclaiming.
# --------------------------------------------------------------------------- #
def _ar_glb_worker():
    try:
        diverging = state.mode == "B" and state.b_view == "deviation"
        mesh = _LAST_MESH["deviation"] if diverging else _LAST_MESH["thickness"]
        if mesh is None:
            raise RuntimeError("Nothing computed yet — run a compute first.")
        params = _params_from_state()
        if diverging:
            scalar = "deviation_mm"
            cmap_name = "blue_white_red"
            center, span = params.mode_b_center, params.mode_b_range_abs
            clim = (center - span, center + span)
        else:
            scalar = "thickness_mm"
            cmap_name = params.mode_a_colormap
            clim = (params.mode_a_range_min, params.mode_a_range_max)

        key = uuid.uuid4().hex[:12]
        out_dir = EXPORTS_DIR / "ar" / key
        out_path = out_dir / "model.glb"
        from core.export.mesh import export_mesh
        export_mesh(mesh, out_path, fmt="glb", scalar_name=scalar,
                    cmap_name=cmap_name, clim=clim)
        url = f"/downloads/ar/{key}/model.glb"
        with state:
            state.ar_glb_busy = False
            state.ar_glb_url = url
            state.ar_glb_path = str(out_path)
            state.ar_glb_msg = f"GLB ready ({out_path.stat().st_size:,} bytes)."
        state.flush()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.ar_glb_busy = False
            state.ar_glb_url = ""
            state.ar_glb_msg = f"GLB export failed: {e}"
        state.flush()


def do_export_ar_glb(*_a, **_k):
    if state.ar_glb_busy:
        return
    with state:
        state.ar_glb_busy = True
        state.ar_glb_msg = "Exporting GLB…"
        state.ar_glb_url = ""
    state.flush()
    threading.Thread(target=_ar_glb_worker, daemon=True).start()


ctrl.do_export_ar_glb = do_export_ar_glb


# --------------------------------------------------------------------------- #
# Share / switcher actions.
# --------------------------------------------------------------------------- #
def refresh_config(*_a, **_k):
    cfg = read_public_config()
    with state:
        state.cfg_public = cfg["public"]
        state.cfg_trame_url = cfg["trame_url"] or ""
        state.cfg_react_url = cfg["react_url"] or ""
        state.share_url = cfg["trame_url"] or FALLBACK_TRAME_URL
        state.other_ui_url = cfg["react_url"] or FALLBACK_REACT_URL
    state.flush()


ctrl.refresh_config = refresh_config

# Poll interval for the Share panel's live public-URL refresh (seconds). Mirrors
# the React app's 6 s /api/config poll: when scripts/share.sh (re)starts a tunnel
# after sleep/wake, the shown URL updates WITHOUT a page reload.
CONFIG_POLL_S = 6.0
_config_poll_stop = threading.Event()


def _config_poll_loop() -> None:
    """Background loop: re-read outputs/public_urls.json every CONFIG_POLL_S and
    push any change to the Share panel state (so the URL refreshes live)."""
    last = None
    while not _config_poll_stop.wait(CONFIG_POLL_S):
        try:
            cfg = read_public_config()
            sig = (cfg["public"], cfg["trame_url"], cfg["react_url"])
            if sig != last:
                last = sig
                refresh_config()
        except Exception:  # noqa: BLE001
            # Transient read error (file mid-rewrite) — keep the last URL.
            pass


def start_config_poll() -> None:
    """Start the live-config polling thread once."""
    t = threading.Thread(target=_config_poll_loop, daemon=True)
    t.start()


ctrl.start_config_poll = start_config_poll


# --------------------------------------------------------------------------- #
# File upload: VFileInput yields a list of {name, content(bytes/base64), size}.
# Accepts every supported format; branches mesh vs volume, single vs bilateral.
# --------------------------------------------------------------------------- #
@state.change("upload_file")
def _on_upload(upload_file, **_k):
    if not upload_file:
        return
    entry = upload_file[0] if isinstance(upload_file, list) else upload_file
    name = entry.get("name", "upload.zip")
    content = entry.get("content")
    if content is None:
        return
    if isinstance(content, str):  # base64 fallback
        import base64
        content = base64.b64decode(content.split(",")[-1])
    dest = WORKDIR / f"upload_{uuid.uuid4().hex[:8]}_{name}"
    dest.parent.mkdir(parents=True, exist_ok=True)
    dest.write_bytes(bytes(content))

    with state:
        state.status = "computing"
        state.status_msg = f"Ingesting {name}…"
    state.flush()

    def _job():
        try:
            _load_source(dest)
            with state:
                _refresh_session_ui()
                if SESSION.get("is_mesh"):
                    state.status_msg = ("Surface mesh loaded — Mode B "
                                        "(comparison / viewing) only.")
                elif state.is_bilateral:
                    state.status_msg = "Bilateral scan loaded (Left / Right)."
                else:
                    state.status_msg = "Single-sided scan loaded (Full)."
                state.status = "idle"
            state.flush()
            recompute()
        except Exception as e:  # noqa: BLE001
            traceback.print_exc()
            with state:
                state.status = "error"
                state.status_msg = f"Upload ingest failed: {e}"
            state.flush()

    threading.Thread(target=_job, daemon=True).start()


# --------------------------------------------------------------------------- #
# UI: registry-driven control renderer.
# --------------------------------------------------------------------------- #
def _render_control(spec: dict):
    key, label = spec["key"], spec["label"]
    unit = f" ({spec['unit']})" if spec.get("unit") else ""
    if spec["control"] == "bool":
        v3.VSwitch(v_model=(key,), label=label, density="compact",
                   hide_details=True, color="primary")
    elif spec["control"] == "enum":
        state[f"{key}_choices"] = spec.get("choices") or []
        v3.VSelect(v_model=(key,), items=(f"{key}_choices",),
                   label=label, density="compact", hide_details=True,
                   variant="outlined")
    else:  # int / float slider
        v3.VSlider(v_model=(key,), label=f"{label}{unit}",
                   min=spec.get("minimum", 0), max=spec.get("maximum", 1),
                   step=spec.get("step", 1), thumb_label=True,
                   density="compact", hide_details=True, color="primary")


with SinglePageWithDrawerLayout(server) as layout:
    layout.title.set_text("3Dorth — cortical bone mapping (trame)")

    with layout.toolbar:
        v3.VSpacer()
        html.Span("Mode", style="font-size:13px;color:#555;margin-right:8px")
        with v3.VBtnToggle(v_model=("mode", "A"), density="compact",
                           mandatory=True, variant="outlined", divided=True):
            v3.VBtn("A", value="A", disabled=("is_mesh_session",))
            v3.VBtn("B", value="B")
        v3.VSwitch(
            v_model=("compare_active",), label="Compare (linked cross-sections)",
            density="compact", hide_details=True, color="primary",
            disabled=("!compare_available",), style="margin-left:16px;flex:none")
        v3.VSwitch(
            v_model=("oblique_active", False),
            label="Oblique cross-section (drag the 3D plane)",
            density="compact", hide_details=True, color="primary",
            disabled=("!oblique_available",), style="margin-left:16px;flex:none")
        v3.VSpacer()
        # Share URL (copyable) + switch-to-the-other-UI.
        v3.VTextField(
            model_value=("share_url",), readonly=True, density="compact",
            hide_details=True, variant="outlined", label="Share URL",
            style="max-width:340px;margin-right:8px", prepend_inner_icon="mdi-share-variant",
            append_inner_icon="mdi-content-copy",
            click_append_inner="navigator.clipboard && navigator.clipboard.writeText(share_url)")
        html.Span("Run ./scripts/share.sh for a public link",
                  v_if="!cfg_public",
                  style="font-size:11px;color:#b26a00;margin-right:8px;max-width:220px")
        v3.VBtn(
            "Switch to {{ other_ui_name }}", size="small", variant="tonal",
            color="primary", prepend_icon="mdi-swap-horizontal",
            style="margin-right:12px",
            click="window.location.assign(other_ui_url)")
        # progress + status
        v3.VProgressLinear(
            indeterminate=True, color="primary",
            v_if="status === 'computing'", style="max-width:120px;margin-right:12px")
        html.Span("{{ status_msg }}",
                  style="font-size:13px;color:#444;max-width:280px;"
                        "overflow:hidden;text-overflow:ellipsis;white-space:nowrap")

    with layout.drawer as drawer:
        drawer.width = 380
        with v3.VCard(flat=True, classes="pa-2"):
            # ---- Session: side + Mode B sub-view + Apply ---------------------
            v3.VCardTitle("Session", classes="text-subtitle-1 pb-1")
            v3.VSelect(v_model=("side",), items=("side_thickness_options",),
                       label="Side (thickness view)", density="compact",
                       hide_details=True, variant="outlined",
                       disabled=("is_mesh_session",))
            html.Div(
                "Both view: left and right are rendered together, each coloured "
                "by its own cortical thickness. The stats/figures below describe "
                "the LEFT side; hover either bone to read its thickness.",
                v_if="side === 'both'",
                style="font-size:11px;color:#666;margin-top:4px;line-height:1.4")
            html.Div(
                "Surface mesh loaded — cortical thickness needs a volume, so "
                "Mode A is disabled. Use Mode B (comparison / viewing).",
                v_if="is_mesh_session",
                style="font-size:11px;color:#b26a00;margin-top:4px;line-height:1.4")
            # Mode B: reference / target / sub-view selector
            with html.Div(v_if="mode === 'B'", classes="mt-2"):
                with v3.VBtnToggle(v_model=("b_view", "thickness"),
                                   density="compact", mandatory=True,
                                   variant="outlined", divided=True,
                                   classes="mb-2"):
                    v3.VBtn("Thickness", value="thickness",
                            disabled=("is_mesh_session",))
                    v3.VBtn("Deviation", value="deviation")
                v3.VSelect(v_model=("ref_side",), items=("side_options",),
                           label="Reference side (on top)", density="compact",
                           hide_details=True, variant="outlined", classes="mb-1")
                v3.VSelect(v_model=("tgt_side",), items=("side_options",),
                           label="Target side", density="compact",
                           hide_details=True, variant="outlined")

            # ---- Region picker (visual thumbnails) ---------------------------
            # Only meaningful for the thickness view of a volume side. Each region
            # shows a small rendered preview + volume/boneness; clicking one
            # selects it and recomputes. The text side-selector above still works.
            with html.Div(
                v_if="!is_mesh_session && !(mode === 'B' && b_view === 'deviation') "
                     "&& side !== 'both'",
                classes="mt-3"):
                v3.VCardSubtitle("Region (click a preview to select)",
                                 classes="px-0 pb-1")
                # Spinner while the previews render (~5-10 s).
                with html.Div(v_if="region_thumbs_loading",
                              classes="d-flex align-center",
                              style="gap:8px;font-size:12px;color:#666;"
                                    "margin:4px 0"):
                    v3.VProgressCircular(indeterminate=True, size="18", width="2",
                                         color="primary")
                    html.Span("{{ region_thumbs_msg }}")
                html.Div("{{ region_thumbs_msg }}",
                         v_if="!region_thumbs_loading && region_thumbs.length === 0",
                         style="font-size:11px;color:#888;margin:4px 0")
                # One clickable card per region.
                with html.Div(v_if="region_thumbs.length > 0",
                              style="display:flex;flex-direction:column;gap:6px;"
                                    "margin-top:4px"):
                    with html.Template(v_for="r in region_thumbs", key="r.label"):
                        with html.Div(
                            click=(ctrl.select_region, "[r.label]"),
                            classes="d-flex align-center",
                            style=("gap:10px;padding:5px 7px;border:1px solid #ddd;"
                                   "border-radius:7px;cursor:pointer;background:#fff"),
                        ):
                            # thumbnail image (or a placeholder chip if null)
                            html.Img(
                                v_if="r.thumb",
                                src=("r.thumb",),
                                style="width:64px;height:64px;object-fit:contain;"
                                      "border:1px solid #eee;border-radius:5px;"
                                      "flex:0 0 auto;background:#fff")
                            html.Div(
                                "no preview", v_if="!r.thumb",
                                style="width:64px;height:64px;display:flex;"
                                      "align-items:center;justify-content:center;"
                                      "border:1px solid #eee;border-radius:5px;"
                                      "flex:0 0 auto;font-size:10px;color:#999;"
                                      "text-align:center")
                            with html.Div(style="min-width:0"):
                                html.Div(
                                    "Region {{ r.label }}",
                                    style="font-size:13px;font-weight:600;color:#222")
                                html.Div(
                                    "{{ r.volume_cm3.toFixed(1) }} cm³ · "
                                    "bone {{ r.boneness.toFixed(2) }}",
                                    style="font-size:11px;color:#1867c0;"
                                          "font-variant-numeric:tabular-nums")

            # Changes now auto-recompute (debounced); this button is an OPTIONAL
            # manual "recompute now" — it is no longer required.
            v3.VBtn("Recompute now", block=True, color="primary",
                    classes="mt-3", click=ctrl.recompute,
                    loading=("status === 'computing'",),
                    prepend_icon="mdi-refresh", variant="tonal")
            html.Div(
                "Every change applies automatically — coloring instantly, "
                "analysis after a brief pause. This button just forces it now.",
                style="font-size:11px;color:#888;margin-top:4px;line-height:1.4")

            v3.VDivider(classes="my-3")

            # ---- File upload (all formats) -----------------------------------
            v3.VCardSubtitle("Load a scan or surface", classes="px-0 pb-1")
            v3.VFileInput(
                v_model=("upload_file", None),
                label="Upload .zip .nii .nii.gz .stl .ply .obj .vtp",
                accept=".zip,.nii,.nii.gz,.stl,.ply,.obj,.vtp",
                density="compact", hide_details=True, variant="outlined",
                prepend_icon="mdi-upload")

            v3.VDivider(classes="my-3")

            # ---- Status alert ------------------------------------------------
            v3.VAlert(
                text=("status_msg",), density="compact", variant="tonal",
                type=("status === 'error' ? 'error' : "
                      "(status === 'computing' ? 'info' : 'success')",),
                classes="mb-3", style="font-size:12px")

            # ---- Live stats --------------------------------------------------
            html.Div(v_html=("stats_html",),
                     style="background:#fafafa;border:1px solid #eee;"
                           "border-radius:6px;padding:8px;margin-bottom:8px")

            # ---- Histogram (distribution of the active scalar) ---------------
            with html.Div(
                v_if="histogram_img",
                style="background:#fafafa;border:1px solid #eee;border-radius:6px;"
                      "padding:8px;margin-bottom:8px"):
                html.Div(
                    "Distribution (of the loaded mesh's own point data)",
                    style="font-size:11px;font-weight:700;letter-spacing:.04em;"
                          "text-transform:uppercase;color:#333;margin-bottom:4px")
                html.Img(src=("histogram_img",),
                         style="width:100%;height:auto;display:block;"
                               "border-radius:4px;background:#fff")

        # ---- Expansion panels: params + Mode B manual anchor + Export --------
        groups: dict[str, list] = {}
        for c in control_specs():
            groups.setdefault(c["group"], []).append(c)
        with v3.VExpansionPanels(multiple=True, variant="accordion"):
            # Registry-driven parameter panel (parity with React).
            for group, specs in groups.items():
                with v3.VExpansionPanel(title=group):
                    with v3.VExpansionPanelText():
                        for spec in specs:
                            _render_control(spec)

            # Manual anchor (Mode B) — only meaningful for a comparison.
            with v3.VExpansionPanel(title="Manual anchor (Mode B)"):
                with v3.VExpansionPanelText():
                    html.Div(
                        "Nudge the auto-registration: translate/rotate the target "
                        "over the reference. Changes auto-recompute (debounced). "
                        "Use the reference/target selectors above to choose which "
                        "side is on top.",
                        style="font-size:11px;color:#666;margin-bottom:8px;line-height:1.4")
                    v3.VSwitch(v_model=("manual_enabled",),
                               label="Apply manual nudge", density="compact",
                               hide_details=True, color="primary", classes="mb-2")
                    html.Div("Translation (mm)",
                             style="font-size:11px;font-weight:700;color:#333;margin:4px 0")
                    v3.VSlider(v_model=("manual_tx",), label="x", min=-20, max=20,
                               step=0.5, thumb_label=True, density="compact",
                               hide_details=True, disabled=("!manual_enabled",))
                    v3.VSlider(v_model=("manual_ty",), label="y", min=-20, max=20,
                               step=0.5, thumb_label=True, density="compact",
                               hide_details=True, disabled=("!manual_enabled",))
                    v3.VSlider(v_model=("manual_tz",), label="z", min=-20, max=20,
                               step=0.5, thumb_label=True, density="compact",
                               hide_details=True, disabled=("!manual_enabled",))
                    html.Div("Rotation (deg)",
                             style="font-size:11px;font-weight:700;color:#333;margin:8px 0 4px")
                    v3.VSlider(v_model=("manual_rx",), label="rx", min=-30, max=30,
                               step=0.5, thumb_label=True, density="compact",
                               hide_details=True, disabled=("!manual_enabled",))
                    v3.VSlider(v_model=("manual_ry",), label="ry", min=-30, max=30,
                               step=0.5, thumb_label=True, density="compact",
                               hide_details=True, disabled=("!manual_enabled",))
                    v3.VSlider(v_model=("manual_rz",), label="rz", min=-30, max=30,
                               step=0.5, thumb_label=True, density="compact",
                               hide_details=True, disabled=("!manual_enabled",))
                    v3.VBtn("Recompute now", block=True, size="small",
                            color="primary", variant="tonal", classes="mt-3",
                            prepend_icon="mdi-refresh",
                            click=ctrl.recompute)

            # ---- Clip + visible-part stats (display-only) --------------------
            # Isolates a sub-part of the CURRENTLY DISPLAYED surface with an
            # axis-aligned clip plane and shows "visible part" stats alongside
            # the whole map's ("total") — recomputed from the CLIPPED mesh's
            # own point-data scalar. Never re-runs the thickness/deviation
            # pipeline (no new geometry, no new measurement).
            with v3.VExpansionPanel(title="Clip / visible-part stats"):
                with v3.VExpansionPanelText():
                    html.Div(
                        "Isolate a sub-part of the surface with an "
                        "axis-aligned clip plane; stats below recompute from "
                        "the CLIPPED mesh's own scalar (display-only — no "
                        "recompute pipeline).",
                        style="font-size:11px;color:#666;margin-bottom:8px;line-height:1.4")
                    v3.VSwitch(v_model=("clip_enabled",), label="Enable clip",
                               density="compact", hide_details=True,
                               color="primary", classes="mb-2")
                    v3.VSelect(
                        v_model=("clip_axis",),
                        items=(["x", "y", "z"],),
                        label="Clip axis", density="compact", hide_details=True,
                        variant="outlined", classes="mb-2",
                        disabled=("!clip_enabled",))
                    v3.VSlider(
                        v_model=("clip_fraction",), label="Plane position",
                        min=0.0, max=1.0, step=0.01, thumb_label=True,
                        density="compact", hide_details=True, color="primary",
                        disabled=("!clip_enabled",))
                    v3.VSwitch(v_model=("clip_invert",), label="Flip visible side",
                               density="compact", hide_details=True,
                               color="primary", classes="mt-2",
                               disabled=("!clip_enabled",))
                    html.Div("{{ clip_msg }}", v_if="clip_msg",
                             style="font-size:11px;color:#666;margin-top:6px")

                    with html.Div(
                        v_if="clip_enabled",
                        style="display:flex;flex-direction:row;gap:10px;margin-top:10px"):
                        with html.Div(style="flex:1 1 0;min-width:0;background:#fafafa;"
                                             "border:1px solid #eee;border-radius:6px;padding:8px"):
                            html.Div("Total (whole map)",
                                     style="font-size:11px;font-weight:700;color:#333;"
                                           "margin-bottom:3px")
                            html.Div(
                                "mean {{ clip_total_stats.mean }} · sd {{ clip_total_stats.sd }}",
                                style="font-size:11px;color:#555")
                            html.Div(
                                "n {{ clip_total_stats.n }}",
                                style="font-size:11px;color:#555")
                        with html.Div(style="flex:1 1 0;min-width:0;background:#eef6ee;"
                                             "border:1px solid #cfe6cf;border-radius:6px;padding:8px"):
                            html.Div("Visible part (clipped)",
                                     style="font-size:11px;font-weight:700;color:#245c24;"
                                           "margin-bottom:3px")
                            html.Div(
                                "mean {{ clip_visible_stats.mean }} · sd {{ clip_visible_stats.sd }}",
                                style="font-size:11px;color:#2f6b2f")
                            html.Div(
                                "n {{ clip_visible_stats.n }}",
                                style="font-size:11px;color:#2f6b2f")

            # ---- Statistics & Figures (publication-style, exportable) --------
            # Renders core.stats.figures on the CURRENTLY COMPUTED result
            # (display-only, same source mesh as the quick histogram above) and
            # offers a PNG/TIFF/JPG + DPI export — mirroring the 3D Export panel
            # below, at parity with the React frontend's figures section.
            with v3.VExpansionPanel(title="Statistics & Figures"):
                with v3.VExpansionPanelText():
                    html.Div(
                        "Publication-style figures for THIS scan only "
                        "(descriptive, single-subject) — a distribution "
                        "histogram and, when >= 2 bone regions were "
                        "segmented, a per-region volume/boneness summary. "
                        "Never a group comparison.",
                        style="font-size:11px;color:#666;margin-bottom:8px;line-height:1.4")

                    html.Div(
                        "Nothing computed yet — run a compute first.",
                        v_if="!Object.keys(stats_figures).length",
                        style="font-size:12px;color:#888")

                    # Descriptive stat block (n, mean±SD, median, IQR, percentiles,
                    # %>1mm / %>2mm) — the same numbers the API's /figures endpoint
                    # returns, surfaced as a compact table (parity with React).
                    with html.Div(
                        v_if="stats_descriptive && stats_descriptive.n",
                        style="background:#fafafa;border:1px solid #eee;"
                              "border-radius:6px;padding:8px;margin-bottom:8px"):
                        html.Div(
                            "Descriptive statistics (single-subject)",
                            style="font-size:11px;font-weight:700;letter-spacing:.04em;"
                                  "text-transform:uppercase;color:#333;margin-bottom:4px")
                        html.Div(
                            "n {{ stats_descriptive.n }} · mean "
                            "{{ stats_descriptive.mean }} ± {{ stats_descriptive.sd }} · "
                            "median {{ stats_descriptive.median }} · IQR "
                            "{{ stats_descriptive.iqr }}",
                            style="font-size:11px;color:#555;line-height:1.6")
                        html.Div(
                            "p5 {{ stats_descriptive.p5 }} · p25 {{ stats_descriptive.p25 }} · "
                            "p75 {{ stats_descriptive.p75 }} · p95 {{ stats_descriptive.p95 }}",
                            style="font-size:11px;color:#555;line-height:1.6")
                        html.Div(
                            "min {{ stats_descriptive.min }} · max {{ stats_descriptive.max }} · "
                            "RMS {{ stats_descriptive.rms }}",
                            style="font-size:11px;color:#555;line-height:1.6")
                        html.Div(
                            ">1 mm {{ stats_descriptive.pct_over_1mm }}% · "
                            ">2 mm {{ stats_descriptive.pct_over_2mm }}%",
                            style="font-size:11px;color:#555;line-height:1.6")

                    with html.Template(
                            v_for="(img, name) in stats_figures", key="name"):
                        with html.Div(
                            style="background:#fafafa;border:1px solid #eee;"
                                  "border-radius:6px;padding:8px;margin-bottom:8px"):
                            html.Div(
                                "{{ ({histogram:'Distribution histogram', "
                                "ecdf:'Cumulative distribution (ECDF)', "
                                "table:'Descriptive table (Table 1)', "
                                "by_region:'Per-region summary'})[name] || name }}",
                                style="font-size:11px;font-weight:700;"
                                      "letter-spacing:.04em;text-transform:uppercase;"
                                      "color:#333;margin-bottom:4px")
                            html.Img(src=("img",),
                                    style="width:100%;height:auto;display:block;"
                                          "border-radius:4px;background:#fff")

                    html.Div(
                        "{{ stats_figures_note }}", v_if="stats_figures_note",
                        style="font-size:10px;color:#888;margin-top:2px;"
                              "margin-bottom:8px;line-height:1.4")

                    v3.VDivider(classes="my-3")

                    v3.VCardSubtitle("Export figures", classes="px-0 pb-1")
                    v3.VSelect(
                        v_model=("figures_export_formats",),
                        items=("figures_export_format_choices",),
                        label="Formats", multiple=True, chips=True,
                        density="compact", hide_details=True, variant="outlined",
                        classes="mb-2")
                    v3.VTextField(
                        v_model=("figures_export_dpi",), label="DPI (raster)",
                        type="number", density="compact", hide_details=True,
                        variant="outlined", classes="mb-2")
                    v3.VBtn("Export figures", block=True, color="primary",
                            classes="mt-1", click=ctrl.do_export_figures,
                            loading=("figures_export_busy",),
                            disabled=("figures_export_busy",))
                    v3.VAlert(text=("figures_export_msg",), v_if="figures_export_msg",
                              density="compact", variant="tonal",
                              type=("figures_export_msg.startsWith('Export failed') ? "
                                    "'error' : 'success'",),
                              classes="mt-2", style="font-size:12px")
                    with html.Div(classes="mt-2",
                                  style="display:flex;flex-wrap:wrap;gap:6px"):
                        with html.Template(
                                v_for="link in figures_export_links",
                                key="link.name + link.fmt"):
                            html.A(
                                "{{ link.name }}.{{ link.fmt }}",
                                href=("link.url",), download=True,
                                target="_blank",
                                style="display:inline-block;padding:4px 10px;"
                                      "background:#1867c0;color:#fff;border-radius:4px;"
                                      "font-size:12px;text-decoration:none;"
                                      "font-weight:600")

            # Export panel.
            with v3.VExpansionPanel(title="Export"):
                with v3.VExpansionPanelText():
                    v3.VSelect(
                        v_model=("export_formats",),
                        items=("export_format_choices",),
                        label="Formats", multiple=True, chips=True,
                        density="compact", hide_details=True, variant="outlined",
                        classes="mb-2")
                    v3.VTextField(
                        v_model=("export_dpi",), label="DPI (raster)",
                        type="number", density="compact", hide_details=True,
                        variant="outlined", classes="mb-2")
                    # Fig-2 measurement overlays (raster/DICOM only). Auto-placed
                    # at the surgical-neck / lesser-tuberosity base; sampled
                    # thickness is read off the computed map, never fabricated.
                    # Only shown for the thickness view (not Mode B deviation).
                    with html.Div(
                        v_if="!(mode === 'B' && b_view === 'deviation')",
                        classes="mb-1"):
                        html.Div("Fig-2 measurement overlays",
                                 style="font-size:11px;font-weight:700;color:#333;"
                                       "margin:4px 0")
                        v3.VSwitch(
                            v_model=("annotate_line",),
                            label="Cortical-thickness sampling line",
                            density="compact", hide_details=True, color="primary")
                        v3.VSwitch(
                            v_model=("annotate_height",),
                            label="Height bracket",
                            density="compact", hide_details=True, color="primary")
                        html.Div(
                            "Auto-placed at the surgical-neck / lesser-tuberosity "
                            "base. Sampled thickness is read off the computed map "
                            "(never fabricated); descriptive / single-subject. "
                            "Applies to raster (PNG/TIFF/JPG) + the DICOM SC.",
                            style="font-size:10px;color:#888;margin:2px 0 6px;"
                                  "line-height:1.4")
                    html.Div("Camera pose",
                             style="font-size:11px;font-weight:700;color:#333;margin:4px 0")
                    v3.VSlider(v_model=("cam_azimuth",), label="azimuth°",
                               min=-180, max=180, step=1, thumb_label=True,
                               density="compact", hide_details=True)
                    v3.VSlider(v_model=("cam_elevation",), label="elevation°",
                               min=-90, max=90, step=1, thumb_label=True,
                               density="compact", hide_details=True)
                    v3.VSlider(v_model=("cam_roll",), label="roll°",
                               min=-180, max=180, step=1, thumb_label=True,
                               density="compact", hide_details=True)
                    v3.VSlider(v_model=("cam_zoom",), label="zoom",
                               min=0.2, max=4.0, step=0.1, thumb_label=True,
                               density="compact", hide_details=True)
                    v3.VBtn("Export", block=True, color="primary",
                            classes="mt-3", click=ctrl.do_export,
                            loading=("export_busy",),
                            disabled=("export_busy",))
                    v3.VAlert(text=("export_msg",), v_if="export_msg",
                              density="compact", variant="tonal",
                              type=("export_msg.startsWith('Export failed') ? "
                                    "'error' : 'success'",),
                              classes="mt-2", style="font-size:12px")
                    # Real download links (one per exported format).
                    with html.Div(classes="mt-2",
                                  style="display:flex;flex-wrap:wrap;gap:6px"):
                        with html.Template(
                                v_for="link in export_links",
                                key="link.fmt"):
                            html.A(
                                "{{ link.fmt }}",
                                href=("link.url",), download=True,
                                target="_blank",
                                style="display:inline-block;padding:4px 10px;"
                                      "background:#1867c0;color:#fff;border-radius:4px;"
                                      "font-size:12px;text-decoration:none;"
                                      "text-transform:uppercase;font-weight:600")

                    v3.VDivider(classes="my-3")

                    # ---- Phase V: AR asset export (GLB) ----------------------
                    v3.VCardSubtitle("AR asset (GLB)", classes="px-0 pb-1")
                    html.Div(
                        "Exports the CURRENTLY DISPLAYED surface (colormap/range "
                        "baked in as per-vertex colour) as a triangle-capped GLB.",
                        style="font-size:11px;color:#666;margin-bottom:6px;line-height:1.4")
                    v3.VBtn("Download GLB for AR", block=True, color="primary",
                            variant="tonal", prepend_icon="mdi-cube-scan",
                            click=ctrl.do_export_ar_glb,
                            loading=("ar_glb_busy",), disabled=("ar_glb_busy",))
                    v3.VAlert(text=("ar_glb_msg",), v_if="ar_glb_msg",
                              density="compact", variant="tonal",
                              type=("ar_glb_msg.startsWith('GLB export failed') ? "
                                    "'error' : 'success'",),
                              classes="mt-2", style="font-size:12px")
                    html.A(
                        "Download model.glb",
                        v_if="ar_glb_url", href=("ar_glb_url",), download=True,
                        target="_blank",
                        style="display:inline-block;margin-top:6px;padding:5px 12px;"
                              "background:#1867c0;color:#fff;border-radius:4px;"
                              "font-size:12px;text-decoration:none;font-weight:600")
                    html.Div(
                        "{{ ar_glb_note }}",
                        style="font-size:10px;color:#888;margin-top:6px;line-height:1.4")

    with layout.content:
        with v3.VContainer(fluid=True, classes="fill-height pa-0",
                           style="position:relative"):
            # Split the content: 3D view (flex) + MPR column (fixed, scrolls).
            with html.Div(style="display:flex;flex-direction:row;width:100%;"
                                 "height:100%;min-height:0"):
                # ---- 3D view (left) --------------------------------------- #
                with html.Div(style="position:relative;flex:1 1 auto;"
                                     "min-width:0;height:100%"):
                    view = plotter_ui(PLOTTER)
                    ctrl.view_update = view.update
                    # Hover tooltip overlay (top-right of the 3D pane).
                    html.Div(
                        v_html=("hover_html",),
                        v_show="hover_active",
                        style="position:absolute;top:12px;right:12px;z-index:10;"
                              "background:rgba(20,22,28,.92);color:#fff;"
                              "padding:8px 12px;border-radius:8px;max-width:260px;"
                              "pointer-events:none;line-height:1.4;"
                              "box-shadow:0 2px 12px rgba(0,0,0,.35)")

                # ---- MPR column (right): 3 array-oriented slice panels ----- #
                with html.Div(
                    v_show="mpr_available && !compare_active && !oblique_active",
                    style="flex:0 0 360px;height:100%;overflow-y:auto;"
                          "border-left:1px solid #e0e0e0;background:#0f1116;"
                          "padding:10px 12px;box-sizing:border-box"):
                    html.Div(
                        "MPR — array-oriented slices",
                        style="color:#e8e8e8;font-size:13px;font-weight:700;"
                              "letter-spacing:.02em;margin-bottom:2px")
                    html.Div(
                        "Side: {{ mpr_side }} · voxel "
                        "({{ mpr_ix }}, {{ mpr_iy }}, {{ mpr_iz }}) · "
                        "click the 3D surface to move the crosshair",
                        style="color:#9aa0aa;font-size:11px;margin-bottom:6px;"
                              "line-height:1.4")
                    html.Div(
                        "{{ mpr_note }}",
                        style="color:#c9a227;font-size:10px;margin-bottom:10px;"
                              "line-height:1.4;border:1px solid #4a3f12;"
                              "background:#1c1808;border-radius:6px;padding:5px 7px")

                    # Window / level for the 2D panels (bone default).
                    with html.Div(style="margin-bottom:8px"):
                        v3.VSlider(
                            v_model=("mpr_window",), label="Window (HU)",
                            min=1, max=4000, step=1, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")
                        v3.VSlider(
                            v_model=("mpr_level",), label="Level (HU)",
                            min=-1000, max=2000, step=1, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")

                    # One panel per plane: label "(array orientation)", the slice
                    # image, and a slider bound to that plane's slice index.
                    def _mpr_panel(title, img_key, idx_key, n_key):
                        with html.Div(style="margin-bottom:12px"):
                            html.Div(
                                title,
                                style="color:#cfd3da;font-size:12px;"
                                      "font-weight:600;margin-bottom:3px")
                            html.Img(
                                src=(img_key,),
                                v_if=f"{img_key}",
                                style="width:100%;height:auto;display:block;"
                                      "background:#000;border:1px solid #2a2e36;"
                                      "border-radius:5px;image-rendering:pixelated")
                            v3.VSlider(
                                v_model=(idx_key,), min=0,
                                max=(f"{n_key} - 1",), step=1,
                                thumb_label=True, density="compact",
                                hide_details=True, color="cyan",
                                classes="mt-1", style="color:#cfd3da")

                    _mpr_panel("Axial (array orientation)", "mpr_img_axial",
                               "mpr_idx_axial", "mpr_n_axial")
                    _mpr_panel("Coronal (array orientation)", "mpr_img_coronal",
                               "mpr_idx_coronal", "mpr_n_coronal")
                    _mpr_panel("Sagittal (array orientation)", "mpr_img_sagittal",
                               "mpr_idx_sagittal", "mpr_n_sagittal")

                # ---- Oblique column (right): arbitrary-tilt reformat ------- #
                # Driven by the pyvista plane widget on the 3D view (drag it to
                # tilt the plane to ANY orientation). BILATERAL sessions show
                # TWO boxes ("Reference bone" / "Target bone") ABOVE the plane
                # controls: the SAME plane, mapped onto the target bone via the
                # cached registration (core.pipeline.map_plane), so both boxes
                # show the same physical cut on both bones. Single-sided/mesh
                # sessions fall back to the single panel below the controls.
                # Display-only: no thickness/deviation recompute.
                with html.Div(
                    v_show="oblique_active",
                    style="flex:0 0 380px;height:100%;overflow-y:auto;"
                          "border-left:1px solid #e0e0e0;background:#0f1116;"
                          "padding:10px 12px;box-sizing:border-box"):
                    html.Div(
                        "Oblique reformat — arbitrary tilt",
                        style="color:#e8e8e8;font-size:13px;font-weight:700;"
                              "letter-spacing:.02em;margin-bottom:2px")
                    html.Div(
                        "Side: {{ oblique_side }} · drag the plane widget in "
                        "the 3D view to re-orient the cut",
                        style="color:#9aa0aa;font-size:11px;margin-bottom:6px;"
                              "line-height:1.4")
                    html.Div(
                        "{{ oblique_note }}",
                        style="color:#c9a227;font-size:10px;margin-bottom:10px;"
                              "line-height:1.4;border:1px solid #4a3f12;"
                              "background:#1c1808;border-radius:6px;padding:5px 7px")
                    html.Div(
                        "origin ({{ oblique_origin[0].toFixed(1) }}, "
                        "{{ oblique_origin[1].toFixed(1) }}, "
                        "{{ oblique_origin[2].toFixed(1) }}) mm · normal "
                        "({{ oblique_normal[0].toFixed(2) }}, "
                        "{{ oblique_normal[1].toFixed(2) }}, "
                        "{{ oblique_normal[2].toFixed(2) }})",
                        style="color:#7d838c;font-size:10px;margin-bottom:8px")

                    # ---- BILATERAL: two boxes ABOVE the plane controls. -----
                    with html.Div(v_if="oblique_bilateral", classes="mb-2"):
                        html.Div("{{ oblique_cmp_msg }}", v_if="oblique_cmp_msg",
                                 style="color:#9aa0aa;font-size:11px;margin-bottom:6px")
                        # Reliability banner — same gate as Compare/API
                        # (inlier_fraction >= 0.30); the target box is never
                        # hidden when unreliable, only flagged.
                        with html.Div(
                            v_if="oblique_cmp_reliable",
                            style="border-radius:6px;padding:5px 8px;margin-bottom:8px;"
                                  "font-size:10px;line-height:1.4;background:#123219;"
                                  "border:1px solid #1e5c2e;color:#8fe3a3"):
                            html.Div("Registration reliable", style="font-weight:700")
                            html.Div(
                                "RMS {{ oblique_cmp_rms }} mm · inlier fraction "
                                "{{ oblique_cmp_inlier_fraction }}")
                        with html.Div(
                            v_if="!oblique_cmp_reliable",
                            style="border-radius:6px;padding:5px 8px;margin-bottom:8px;"
                                  "font-size:10px;line-height:1.4;background:#332405;"
                                  "border:1px solid #7a5a10;color:#f0c96b"):
                            html.Div("Registration UNRELIABLE — target reformat not trustworthy",
                                     style="font-weight:700")
                            html.Div(
                                "RMS {{ oblique_cmp_rms }} mm · inlier fraction "
                                "{{ oblique_cmp_inlier_fraction }} (< 0.30)")
                        with html.Div(style="display:flex;flex-direction:row;gap:8px"):
                            with html.Div(style="flex:1 1 0;min-width:0"):
                                html.Div(
                                    "Reference bone ({{ oblique_ref_side }})",
                                    style="color:#cfd3da;font-size:12px;font-weight:700;"
                                          "margin-bottom:3px")
                                html.Img(
                                    src=("oblique_ref_img",), v_if="oblique_ref_img",
                                    style="width:100%;height:auto;display:block;"
                                          "background:#000;border:1px solid #2a2e36;"
                                          "border-radius:5px;image-rendering:pixelated")
                            with html.Div(style="flex:1 1 0;min-width:0"):
                                html.Div(
                                    "Target bone ({{ oblique_tgt_side }})",
                                    style="color:#cfd3da;font-size:12px;font-weight:700;"
                                          "margin-bottom:3px")
                                html.Img(
                                    src=("oblique_tgt_img",), v_if="oblique_tgt_img",
                                    style="width:100%;height:auto;display:block;"
                                          "background:#000;border:1px solid #2a2e36;"
                                          "border-radius:5px;image-rendering:pixelated;"
                                          "opacity:{{ oblique_cmp_reliable ? 1 : 0.55 }}")

                    with html.Div(style="margin-bottom:8px"):
                        v3.VSlider(
                            v_model=("oblique_window",), label="Window (HU)",
                            min=1, max=4000, step=1, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")
                        v3.VSlider(
                            v_model=("oblique_level",), label="Level (HU)",
                            min=-1000, max=2000, step=1, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")
                        v3.VSlider(
                            v_model=("oblique_size_mm",), label="Field of view (mm)",
                            min=40, max=400, step=5, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")

                    # ---- Single-panel fallback (non-bilateral sessions). ----
                    html.Img(
                        src=("oblique_img",), v_if="!oblique_bilateral && oblique_img",
                        style="width:100%;height:auto;display:block;"
                              "background:#000;border:1px solid #2a2e36;"
                              "border-radius:5px;image-rendering:pixelated")
                    html.Div(
                        "No reformat yet — drag the 3D plane widget.",
                        v_if="!oblique_bilateral && !oblique_img",
                        style="color:#888;font-size:11px;margin-top:8px")

                # ---- Compare column (right): Phase IV linked cross-sections - #
                # Reference volume / Target volume panels side by side, driven by
                # the SAME crosshair math as the Phase III MPR, mapped through the
                # cached compare_registration 4x4. Shown INSTEAD of the plain MPR
                # column while compare mode is active (same real estate).
                with html.Div(
                    v_show="compare_active && !oblique_active",
                    style="flex:0 0 640px;height:100%;overflow-y:auto;"
                          "border-left:1px solid #e0e0e0;background:#0f1116;"
                          "padding:10px 12px;box-sizing:border-box"):
                    html.Div(
                        "Compare — linked cross-sections",
                        style="color:#e8e8e8;font-size:13px;font-weight:700;"
                              "letter-spacing:.02em;margin-bottom:2px")
                    html.Div(
                        "click the 3D REFERENCE surface to move the crosshair "
                        "(target panels follow via the cached registration)",
                        style="color:#9aa0aa;font-size:11px;margin-bottom:6px;"
                              "line-height:1.4")
                    html.Div(
                        "{{ cmp_note }}",
                        style="color:#c9a227;font-size:10px;margin-bottom:8px;"
                              "line-height:1.4;border:1px solid #4a3f12;"
                              "background:#1c1808;border-radius:6px;padding:5px 7px")

                    # Busy / error line.
                    html.Div("{{ cmp_msg }}", v_if="cmp_msg",
                              style="color:#9aa0aa;font-size:11px;margin-bottom:8px")

                    # Reliability banner: green (reliable) vs amber (low overlap) —
                    # the SAME gate as the API (inlier_fraction >= 0.30). Never
                    # hidden when unreliable; the matched target slice is shown
                    # regardless, just flagged as not trustworthy.
                    with html.Div(
                        v_if="compare_available && cmp_reliable",
                        style="border-radius:6px;padding:6px 9px;margin-bottom:10px;"
                              "font-size:11px;line-height:1.4;background:#123219;"
                              "border:1px solid #1e5c2e;color:#8fe3a3"):
                        html.Div("Registration reliable",
                                 style="font-weight:700;margin-bottom:2px")
                        html.Div(
                            "RMS {{ cmp_rms }} mm · inlier fraction "
                            "{{ cmp_inlier_fraction }} · {{ cmp_reg_note }}")
                    with html.Div(
                        v_if="compare_available && !cmp_reliable",
                        style="border-radius:6px;padding:6px 9px;margin-bottom:10px;"
                              "font-size:11px;line-height:1.4;background:#332405;"
                              "border:1px solid #7a5a10;color:#f0c96b"):
                        html.Div("Registration UNRELIABLE — target slice not trustworthy",
                                 style="font-weight:700;margin-bottom:2px")
                        html.Div(
                            "RMS {{ cmp_rms }} mm · inlier fraction "
                            "{{ cmp_inlier_fraction }} (< 0.30) · {{ cmp_reg_note }}")
                    html.Div(
                        "Compare needs two distinct loaded volume sides.",
                        v_if="!compare_available",
                        style="color:#c77;font-size:11px;margin-bottom:10px")

                    # Window / level shared by both sides' panels.
                    with html.Div(style="margin-bottom:8px"):
                        v3.VSlider(
                            v_model=("cmp_window",), label="Window (HU)",
                            min=1, max=4000, step=1, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")
                        v3.VSlider(
                            v_model=("cmp_level",), label="Level (HU)",
                            min=-1000, max=2000, step=1, thumb_label=True,
                            density="compact", hide_details=True, color="cyan",
                            style="color:#cfd3da")

                    # Two-column layout: Reference volume | Target volume.
                    with html.Div(style="display:flex;flex-direction:row;gap:10px"):
                        with html.Div(style="flex:1 1 0;min-width:0"):
                            html.Div(
                                "Reference volume ({{ cmp_ref_side }})",
                                style="color:#cfd3da;font-size:12px;font-weight:700;"
                                      "margin-bottom:4px")
                            html.Div(
                                "voxel ({{ cmp_ix }}, {{ cmp_iy }}, {{ cmp_iz }})",
                                style="color:#7d838c;font-size:10px;margin-bottom:4px")

                            def _cmp_ref_panel(title, img_key, idx_key, n_key):
                                with html.Div(style="margin-bottom:10px"):
                                    html.Div(title,
                                             style="color:#cfd3da;font-size:11px;"
                                                   "font-weight:600;margin-bottom:2px")
                                    html.Img(
                                        src=(img_key,), v_if=f"{img_key}",
                                        style="width:100%;height:auto;display:block;"
                                              "background:#000;border:1px solid #2a2e36;"
                                              "border-radius:5px;image-rendering:pixelated")
                                    v3.VSlider(
                                        v_model=(idx_key,), min=0,
                                        max=(f"{n_key} - 1",), step=1,
                                        thumb_label=True, density="compact",
                                        hide_details=True, color="cyan",
                                        classes="mt-1", style="color:#cfd3da")

                            _cmp_ref_panel("Axial (array orientation)",
                                          "cmp_ref_img_axial", "cmp_idx_axial", "cmp_n_axial")
                            _cmp_ref_panel("Coronal (array orientation)",
                                          "cmp_ref_img_coronal", "cmp_idx_coronal", "cmp_n_coronal")
                            _cmp_ref_panel("Sagittal (array orientation)",
                                          "cmp_ref_img_sagittal", "cmp_idx_sagittal", "cmp_n_sagittal")

                        with html.Div(style="flex:1 1 0;min-width:0"):
                            html.Div(
                                "Target volume ({{ cmp_tgt_side }})",
                                style="color:#cfd3da;font-size:12px;font-weight:700;"
                                      "margin-bottom:4px")
                            html.Div(
                                "matched voxel ({{ cmp_tgt_ix }}, {{ cmp_tgt_iy }}, "
                                "{{ cmp_tgt_iz }})",
                                v_if="cmp_tgt_in_bounds",
                                style="color:#7d838c;font-size:10px;margin-bottom:4px")
                            html.Div(
                                "matched voxel ({{ cmp_tgt_ix }}, {{ cmp_tgt_iy }}, "
                                "{{ cmp_tgt_iz }}) — OUT OF BOUNDS",
                                v_if="!cmp_tgt_in_bounds",
                                style="color:#e08b8b;font-size:10px;margin-bottom:4px")

                            # Static (non-interactive) images: this side FOLLOWS the
                            # reference crosshair — it is not independently draggable.
                            def _cmp_tgt_panel(title, img_key):
                                with html.Div(style="margin-bottom:10px"):
                                    html.Div(title,
                                             style="color:#cfd3da;font-size:11px;"
                                                   "font-weight:600;margin-bottom:2px")
                                    html.Img(
                                        src=(img_key,), v_if=f"{img_key}",
                                        style="width:100%;height:auto;display:block;"
                                              "background:#000;border:1px solid #2a2e36;"
                                              "border-radius:5px;image-rendering:pixelated;"
                                              "opacity:{{ cmp_reliable ? 1 : 0.55 }}")

                            _cmp_tgt_panel("Axial (array orientation)", "cmp_tgt_img_axial")
                            _cmp_tgt_panel("Coronal (array orientation)", "cmp_tgt_img_coronal")
                            _cmp_tgt_panel("Sagittal (array orientation)", "cmp_tgt_img_sagittal")


# --------------------------------------------------------------------------- #
# Startup: load the demo scan (server-side) and do an initial Mode A compute.
# --------------------------------------------------------------------------- #
def _bootstrap():
    refresh_config()
    start_config_poll()  # live Share-URL refresh (mirrors React's 6 s poll)
    if DEMO_ZIP is None:
        with state:
            state.status = "error"
            state.status_msg = ("No demo dataset found. Build one with "
                                "scripts/make_demo.py, or upload a scan.")
        state.flush()
        return
    try:
        _load_source(DEMO_ZIP, layout="bilateral")
        with state:
            _refresh_session_ui()
            state.status_msg = "Demo scan loaded. Computing…"
        state.flush()
        recompute()
    except Exception as e:  # noqa: BLE001
        traceback.print_exc()
        with state:
            state.status = "error"
            state.status_msg = f"Startup load failed: {e}"
        state.flush()


if __name__ == "__main__":
    _bootstrap()
    server.start(port=8081)
